              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div className="form-group">
                  <label className="form-label">Dia</label>
                  <input
                    type="date"
                    className="form-input"
                    value={newData}
                    onChange={(e) => setNewData(e.target.value)}
