interface MiniMonthProps {
  year: number;
  month: number;
  countByDate: Record<string, number>;
  today: Date;
  onDayClick: (d: Date) => void;
}

const MiniMonth: React.FC<MiniMonthProps> = ({ year, month, countByDate, today, onDayClick }) => {
  const first = new Date(year, month, 1);
  const offset = (first.getDay() + 6) % 7; // 0 = segunda
  const total = daysInMonth(year, month);

  const cells: ({ d: number; date: Date } | null)[] = [];
  for (let i = 0; i < offset; i++) cells.push(null);
  for (let d = 1; d <= total; d++) cells.push({ d, date: new Date(year, month, d) });
  while (cells.length % 7 !== 0) cells.push(null);

  return (
    <div className="card" style={{ padding: '16px' }}>
      <div style={{
        display: 'flex',
        alignItems: 'center',
        gap: '6px',
        marginBottom: '12px',
        color: 'var(--color-primary)',
      }}>
        <CalendarRange size={14} />
        <h4 style={{
          fontSize: '13px',
          fontWeight: 600,
          color: 'var(--color-text-main)',
          textTransform: 'capitalize',
        }}>
          {MESES[month]}
        </h4>
      </div>

      {/* Header dos dias da semana */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(7, 1fr)',
        gap: '2px',
        marginBottom: '6px',
      }}>
        {DIAS_SEMANA_MIN.map((d, i) => (
          <div key={i} style={{
            fontSize: '10px',
            textAlign: 'center',
            color: 'var(--color-text-muted)',
            fontWeight: 500,
          }}>
            {d}
          </div>
        ))}
      </div>

      {/* Células */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px' }}>
        {cells.map((cell, i) => {
          if (!cell) return <div key={i} style={{ height: '28px' }} />;
          const iso = toISODate(cell.date);
          const count = countByDate[iso] || 0;
          const isToday = isSameDay(cell.date, today);
          return (
            <button
              key={i}
              onClick={() => onDayClick(cell.date)}
              title={count ? `${count} agendamento(s)` : 'Disponível'}
              style={{
                position: 'relative',
                height: '28px',
                fontSize: '11px',
                fontWeight: isToday ? 700 : 500,
                color: isToday ? '#FFFFFF' : 'var(--color-text-main)',
                background: isToday
                  ? 'var(--color-primary)'
                  : count > 0
                  ? 'var(--color-primary-light)'
                  : 'transparent',
                border: 'none',
                borderRadius: '6px',
                cursor: 'pointer',
                transition: 'var(--transition-smooth)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
              }}
              onMouseEnter={(e) => {
                if (!isToday) (e.currentTarget as HTMLButtonElement).style.background = 'var(--color-border)';
              }}
              onMouseLeave={(e) => {
                if (!isToday) (e.currentTarget as HTMLButtonElement).style.background =
                  count > 0 ? 'var(--color-primary-light)' : 'transparent';
              }}
            >
              {cell.d}
              {count > 0 && !isToday && (
                <span
                  style={{
                    position: 'absolute',
                    bottom: '3px',
                    width: '4px',
                    height: '4px',
                    borderRadius: '50%',
                    background: 'var(--color-primary)',
                  }}
                />
              )}
            </button>
          );
        })}
      </div>
    </div>
  );
};

import React, { useCallback, useEffect, useState } from 'react';
import { api } from '../lib/api';
import type { ClinicaPublica, ProcedimentoPublico, ProfissionalPublico, SlotOcupado } from '../types';

// ─── helpers ────────────────────────────────────────────────────────────────

function timeToMinutes(t: string): number {
  const [h, m] = t.split(':').map(Number);
  return h * 60 + m;
}

function minutesToTime(mins: number): string {
  const h = Math.floor(mins / 60).toString().padStart(2, '0');
  const m = (mins % 60).toString().padStart(2, '0');
  return `${h}:${m}`;
}

function calcHoraFim(horaInicio: string, duracaoMinutos: number): string {
  return minutesToTime(timeToMinutes(horaInicio) + duracaoMinutos);
}

function generateAvailableSlots(
  bookedSlots: SlotOcupado[],
  duracaoMinutos: number,
  dateStr: string,
  minAdvanceHoras: number,
): string[] {
  const CLINIC_START = 8 * 60;
  const CLINIC_END   = 18 * 60;
  const INTERVAL     = 15;

  const now      = new Date();
  const selected = new Date(dateStr + 'T00:00:00');
  const isToday  = selected.toDateString() === now.toDateString();
  const minAdvMin = minAdvanceHoras * 60;
  const nowMins  = now.getHours() * 60 + now.getMinutes();

  const slots: string[] = [];
  for (let start = CLINIC_START; start + duracaoMinutos <= CLINIC_END; start += INTERVAL) {
    if (isToday && start - nowMins < minAdvMin) continue;
    const end = start + duracaoMinutos;
    const blocked = bookedSlots.some(b => {
      const bS = timeToMinutes(b.horaInicio);
      const bE = timeToMinutes(b.horaFim);
      return start < bE && end > bS;
    });
    if (!blocked) slots.push(minutesToTime(start));
  }
  return slots;
}

function formatPhone(v: string): string {
  const n = v.replace(/\D/g, '').slice(0, 11);
  if (n.length <= 2)  return n.length ? `(${n}` : '';
  if (n.length <= 6)  return `(${n.slice(0, 2)}) ${n.slice(2)}`;
  if (n.length <= 10) return `(${n.slice(0, 2)}) ${n.slice(2, 6)}-${n.slice(6)}`;
  return `(${n.slice(0, 2)}) ${n.slice(2, 7)}-${n.slice(7)}`;
}

function formatPrice(v: number): string {
  return v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

function isoToDisplay(dateStr: string): string {
  const [y, m, d] = dateStr.split('-');
  return `${d}/${m}/${y}`;
}

function buildCalendarDays(year: number, month: number): (number | null)[] {
  const firstDay = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const days: (number | null)[] = Array(firstDay).fill(null);
  for (let d = 1; d <= daysInMonth; d++) days.push(d);
  return days;
}

