                      <span style={{ fontSize: '14px', fontWeight: 700, color: PRIMARY }}>{formatPrice(p.preco)}</span>
                    </div>
                    <div style={{ display: 'flex', gap: '12px', fontSize: '12px', color: TEXT_MUTED }}>
                      <span>⏱ {p.duracaoMinutos} min</span>
