source:
import React, { useCallback, useEffect, useState } from 'react';
import {
  AlertTriangle,
  CalendarRange,
  CheckCircle2,
  MessageCircle,
  Phone,
  Plus,
  Search,
  Trash2,
  UserX,
  X,
  Clock,
  TrendingDown,
  Users,
  RefreshCw,
} from 'lucide-react';
import { api } from '../lib/api';
import type {
  Cliente,
  ContaReceber,
  CrcAcaoContexto,
  CrcFalta,
  CrcSemReagendamento,
  MembroEquipe,
  TemplateMensagem,
} from '../types';

// ── Helpers ─────────────────────────────────────────────────────────────

function formatDate(iso: string): string {
  if (!iso) return '';
  const [y, m, d] = iso.split('-');
  return `${d}/${m}/${y}`;
}

function formatCurrency(v: number): string {
  return v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

function todayISO(): string {
  return new Date().toISOString().split('T')[0];
}

function openWhatsApp(telefone: string, mensagem: string) {
  const num = telefone.replace(/\D/g, '');
  const phone = num.startsWith('55') ? num : `55${num}`;
  window.open(`https://wa.me/${phone}?text=${encodeURIComponent(mensagem)}`, '_blank');
}

function interpolate(template: string, vars: Record<string, string>): string {
  return template.replace(/\{\{(\w+)\}\}/g, (_, k) => vars[k] ?? `{{${k}}}`);
}

// ── Tipos locais ─────────────────────────────────────────────────────────

type TabId = 'faltas' | 'inadimplentes' | 'sem_retorno';

interface ContaForm {
  clienteId: string;
  clienteNome: string;
  descricao: string;
  valor: number;
  dataVencimento: string;
  observacoes: string;
}

const EMPTY_CONTA: ContaForm = {
  clienteId:       '',
  clienteNome:     '',
  descricao:       '',
  valor:           0,
  dataVencimento:  todayISO(),
  observacoes:     '',
};

const PERIODO_OPTIONS = [
  { label: 'Últimos 7 dias',  value: 7 },
  { label: 'Últimos 15 dias', value: 15 },
  { label: 'Últimos 30 dias', value: 30 },
];

const SEM_RETORNO_OPCOES = [
  { label: '30+ dias sem visita',  value: 30 },
  { label: '60+ dias sem visita',  value: 60 },
  { label: '90+ dias sem visita',  value: 90 },
  { label: '120+ dias sem visita', value: 120 },
];

// ── Componente ────────────────────────────────────────────────────────────

interface CRCCentralProps {
  userId: string;
  userName: string;
  onAgendar?: () => void;
  permissoes?: import('../types').Permissoes | null;
}

export const CRCCentral: React.FC<CRCCentralProps> = ({ userId, userName, onAgendar, permissoes }) => {
  const pode = (acao: 'ver' | 'criar' | 'editar' | 'deletar') =>
    !permissoes || !!(permissoes['crc']?.[acao]);
  const [tab, setTab] = useState<TabId>('faltas');

  // Dados
  const [faltas, setFaltas]           = useState<CrcFalta[]>([]);
  const [inadimplentes, setInadimpl]  = useState<ContaReceber[]>([]);
  const [semRetorno, setSemRetorno]   = useState<CrcSemReagendamento[]>([]);
  const [clientes, setClientes]       = useState<Cliente[]>([]);
  const [equipe, setEquipe]           = useState<MembroEquipe[]>([]);
  const [templates, setTemplates]     = useState<TemplateMensagem[]>([]);

  // Filtros
  const [periodoFaltas, setPeriodoFaltas]     = useState(15);
  const [profFiltro, setProfFiltro]           = useState('');
  const [buscaFaltas, setBuscaFaltas]         = useState('');
  const [periodoSemRetorno, setPeriodoSemRetorno] = useState(60);
  const [buscaSemRetorno, setBuscaSemRetorno] = useState('');
  const [buscaInadimpl, setBuscaInadimpl]     = useState('');

  // Loading / saving
  const [loadingFaltas, setLoadingFaltas]         = useState(true);
  const [loadingInadimpl, setLoadingInadimpl]     = useState(true);
  const [loadingSemRetorno, setLoadingSemRetorno] = useState(true);
  const [saving, setSaving]                       = useState(false);

  // Seleção múltipla
  const [selectedFaltas, setSelectedFaltas]       = useState<Set<string>>(new Set());
  const [selectedInadimpl, setSelectedInadimpl]   = useState<Set<string>>(new Set());
  const [selectedSemRet, setSelectedSemRet]       = useState<Set<string>>(new Set());

  // Modal de mensagem
  const [showMsgModal, setShowMsgModal]           = useState(false);
  const [msgRecipients, setMsgRecipients]         = useState<{ clienteId: string; nome: string; telefone: string }[]>([]);
  const [msgContexto, setMsgContexto]             = useState<CrcAcaoContexto>('falta');
  const [templateId, setTemplateId]               = useState('');
  const [msgText, setMsgText]                     = useState('');
  const [msgVars, setMsgVars]                     = useState<Record<string, string>>({});

  // Modal de nova conta a receber
  const [showContaModal, setShowContaModal]       = useState(false);
  const [contaForm, setContaForm]                 = useState<ContaForm>(EMPTY_CONTA);
  const [clienteBusca, setClienteBusca]           = useState('');
  const [clienteSugestoes, setClienteSugestoes]   = useState<Cliente[]>([]);

  // ── Carga ────────────────────────────────────────────────────────────

  const loadFaltas = useCallback(async () => {
    setLoadingFaltas(true);
    try {
      const data = await api.getFaltasRecentes(userId, periodoFaltas);
      setFaltas(data);
    } catch (e) { console.error(e); }
    finally { setLoadingFaltas(false); }
  }, [userId, periodoFaltas]);

  const loadInadimpl = useCallback(async () => {
    setLoadingInadimpl(true);
    try {
      const data = await api.getInadimplentes(userId);
      setInadimpl(data);
    } catch (e) { console.error(e); }
    finally { setLoadingInadimpl(false); }
  }, [userId]);

  const loadSemRetorno = useCallback(async () => {
    setLoadingSemRetorno(true);
    try {
      const data = await api.getPacientesSemReagendamento(userId, periodoSemRetorno);
      setSemRetorno(data);
    } catch (e) { console.error(e); }
    finally { setLoadingSemRetorno(false); }
  }, [userId, periodoSemRetorno]);

  useEffect(() => {
    api.getClientes(userId).then(setClientes).catch(console.error);
    api.getEquipe(userId).then(setEquipe).catch(console.error);
    api.getTemplatesMensagens(userId).then(setTemplates).catch(console.error);
  }, [userId]);

  useEffect(() => { if (tab === 'faltas')        loadFaltas();     }, [tab, loadFaltas]);
  useEffect(() => { if (tab === 'inadimplentes') loadInadimpl();   }, [tab, loadInadimpl]);
  useEffect(() => { if (tab === 'sem_retorno')   loadSemRetorno(); }, [tab, loadSemRetorno]);

  // ── Sugestões de clientes ────────────────────────────────────────────

  useEffect(() => {
    if (!clienteBusca.trim()) { setClienteSugestoes([]); return; }
    const q = clienteBusca.toLowerCase();
    setClienteSugestoes(clientes.filter((c) => c.nome.toLowerCase().includes(q)).slice(0, 6));
  }, [clienteBusca, clientes]);

  // ── Filtros aplicados ────────────────────────────────────────────────

  const faltasFiltradas = faltas.filter((f) => {
    const matchProf  = !profFiltro || f.profissional === profFiltro;
    const matchBusca = !buscaFaltas || f.clienteNome.toLowerCase().includes(buscaFaltas.toLowerCase());
    return matchProf && matchBusca;
  });

  const inadimplFiltrados = inadimplentes.filter((c) =>
    !buscaInadimpl || c.clienteNome.toLowerCase().includes(buscaInadimpl.toLowerCase())
  );

  const semRetornoFiltrados = semRetorno.filter((s) =>
    !buscaSemRetorno || s.clienteNome.toLowerCase().includes(buscaSemRetorno.toLowerCase())
  );

  // ── Helpers de seleção ───────────────────────────────────────────────

  function toggleFalta(id: string) {
    setSelectedFaltas((prev) => { const s = new Set(prev); s.has(id) ? s.delete(id) : s.add(id); return s; });
  }
  function toggleInadimpl(id: string) {
    setSelectedInadimpl((prev) => { const s = new Set(prev); s.has(id) ? s.delete(id) : s.add(id); return s; });
  }
  function toggleSemRet(id: string) {
    setSelectedSemRet((prev) => { const s = new Set(prev); s.has(id) ? s.delete(id) : s.add(id); return s; });
  }

  // ── Abrir modal de mensagem ──────────────────────────────────────────

  function openMsgModal(
    recipients: { clienteId: string; nome: string; telefone: string }[],
    contexto: CrcAcaoContexto,
    extraVars?: Record<string, string>
  ) {
    setMsgRecipients(recipients);
    setMsgContexto(contexto);
    setMsgVars(extraVars ?? {});
    const firstTemplate = templates[0];
    if (firstTemplate) {
      setTemplateId(firstTemplate.id);
      const vars = { nome: recipients[0]?.nome ?? '', clinica: userName, ...(extraVars ?? {}) };
      setMsgText(interpolate(firstTemplate.texto, vars));
    } else {
      setTemplateId('');
      setMsgText('');
    }
    setShowMsgModal(true);
  }

  function handleTemplateChange(id: string) {
    setTemplateId(id);
    const t = templates.find((t) => t.id === id);
    if (t && msgRecipients.length === 1) {
      const vars = { nome: msgRecipients[0].nome, clinica: userName, ...msgVars };
      setMsgText(interpolate(t.texto, vars));
    } else if (t) {
      setMsgText(t.texto);
    }
  }

  async function handleEnviarMensagem() {
    if (!msgText.trim()) { alert('Digite uma mensagem.'); return; }
    setSaving(true);
    try {
      for (const rec of msgRecipients) {
        if (!rec.telefone) continue;
        const personalizado = interpolate(msgText, { nome: rec.nome, clinica: userName, ...msgVars });
        openWhatsApp(rec.telefone, personalizado);
        await api.registrarCrcAcao(
          { clienteId: rec.clienteId, tipo: 'mensagem_whatsapp', contexto: msgContexto, observacao: personalizado.slice(0, 200), usuarioNome: userName },
          userId
        );
      }
      setShowMsgModal(false);
      setSelectedFaltas(new Set());
      setSelectedInadimpl(new Set());
      setSelectedSemRet(new Set());
    } catch (e: any) {
      alert(e?.message ?? 'Erro ao registrar ação.');
    } finally {
      setSaving(false);
    }
  }

  // ── Ações individuais ────────────────────────────────────────────────

  async function handleMarcarPago(conta: ContaReceber) {
    setSaving(true);
    try {
      await api.marcarContaPaga(conta.id, todayISO(), userId);
      await api.registrarCrcAcao(
        { clienteId: conta.clienteId, tipo: 'cobranca', contexto: 'inadimplente', observacao: `Pagamento registrado: ${formatCurrency(conta.valor)}`, usuarioNome: userName },
        userId
      );
      await loadInadimpl();
    } catch (e: any) {
      alert(e?.message ?? 'Erro ao marcar como pago.');
    } finally {
      setSaving(false);
    }
  }

  async function handleDeleteConta(id: string) {
    if (!confirm('Excluir esta conta?')) return;
    try {
      await api.deleteContaReceber(id, userId);
      await loadInadimpl();
    } catch (e: any) {
      alert(e?.message ?? 'Erro ao excluir conta.');
    }
  }

  async function handleNaoRetorna(s: CrcSemReagendamento) {
    if (!confirm(`Marcar ${s.clienteNome} como "Não retorna mais"? Ele sairá desta lista permanentemente.`)) return;
    try {
      await api.marcarClienteNaoRetorna(s.clienteId, true, userId);
      await api.registrarCrcAcao(
        { clienteId: s.clienteId, tipo: 'nao_retorna', contexto: 'sem_reagendamento', usuarioNome: userName },
        userId
      );
      await loadSemRetorno();
    } catch (e: any) {
      alert(e?.message ?? 'Erro.');
    }
  }

  async function handleSaveConta() {
    if (!contaForm.clienteId) { alert('Selecione um cliente.'); return; }
    if (!contaForm.descricao.trim()) { alert('Informe a descrição.'); return; }
    if (contaForm.valor <= 0) { alert('Informe um valor válido.'); return; }
    setSaving(true);
    try {
      await api.createContaReceber(
        { clienteId: contaForm.clienteId, descricao: contaForm.descricao, valor: contaForm.valor, dataVencimento: contaForm.dataVencimento, observacoes: contaForm.observacoes || null },
        userId
      );
      setShowContaModal(false);
      setContaForm(EMPTY_CONTA);
      setClienteBusca('');
      await loadInadimpl();
    } catch (e: any) {
      alert(e?.message ?? 'Erro ao salvar conta.');
    } finally {
      setSaving(false);
    }
  }

  // ── Ação em lote ────────────────────────────────────────────────────

  function handleBulkFaltas() {
    const recipients = faltasFiltradas
      .filter((f) => selectedFaltas.has(f.agendamentoId))
      .map((f) => ({ clienteId: f.clienteId, nome: f.clienteNome, telefone: f.telefone }));
    if (!recipients.length) return;
    openMsgModal(recipients, 'falta');
  }

  function handleBulkInadimpl() {
    const recipients = inadimplFiltrados
      .filter((c) => selectedInadimpl.has(c.id))
      .map((c) => ({ clienteId: c.clienteId, nome: c.clienteNome, telefone: c.telefone }));
    if (!recipients.length) return;
    openMsgModal(recipients, 'inadimplente');
  }

  function handleBulkSemRetorno() {
    const recipients = semRetornoFiltrados
      .filter((s) => selectedSemRet.has(s.clienteId))
      .map((s) => ({ clienteId: s.clienteId, nome: s.clienteNome, telefone: s.telefone }));
    if (!recipients.length) return;
    openMsgModal(recipients, 'sem_reagendamento');
  }

  // ── Estatísticas header ──────────────────────────────────────────────

  const statsFaltas      = faltas.length;
  const statsInadimpl    = inadimplentes.length;
  const statsSemRetorno  = semRetorno.length;

  // ── Render ────────────────────────────────────────────────────────────

  return (
    <div style={{ padding: '24px', maxWidth: 1100, margin: '0 auto' }}>

      {/* Header */}
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ margin: 0, fontSize: 22, fontWeight: 700, color: 'var(--color-text-main)' }}>Central de Relacionamento</h1>
        <p style={{ margin: '4px 0 0', fontSize: 13, color: 'var(--color-text-muted)' }}>
          Faltas, inadimplentes e pacientes sem retorno — em um único lugar.
        </p>
      </div>

      {/* Chips de resumo */}
      <div style={{ display: 'flex', gap: 12, marginBottom: 24, flexWrap: 'wrap' }}>
        <SummaryChip icon={<AlertTriangle size={14} />} label="Faltas recentes" value={statsFaltas} color="#C2410C" bg="#FFF7ED" border="#FED7AA" onClick={() => setTab('faltas')} />
        <SummaryChip icon={<TrendingDown size={14} />} label="Inadimplentes"   value={statsInadimpl} color="#B91C1C" bg="#FEF2F2" border="#FECACA" onClick={() => setTab('inadimplentes')} />
        <SummaryChip icon={<Clock size={14} />}         label="Sem retorno"      value={statsSemRetorno} color="#1D4ED8" bg="#EFF6FF" border="#BFDBFE" onClick={() => setTab('sem_retorno')} />
      </div>

      {/* Tabs */}
      <div style={{ display: 'flex', gap: 4, borderBottom: '1px solid var(--color-border)', marginBottom: 24 }}>
        {([
          { id: 'faltas',         label: 'Faltas Recentes',    count: statsFaltas },
          { id: 'inadimplentes',  label: 'Inadimplentes',      count: statsInadimpl },
          { id: 'sem_retorno',    label: 'Sem Reagendamento',  count: statsSemRetorno },
        ] as { id: TabId; label: string; count: number }[]).map(({ id, label, count }) => (
          <button
            key={id}
            onClick={() => setTab(id)}
            style={{
              padding: '8px 16px', border: 'none', cursor: 'pointer', background: 'transparent',
              fontSize: 14, fontWeight: tab === id ? 600 : 400,
              color: tab === id ? 'var(--color-primary)' : 'var(--color-text-muted)',
              borderBottom: tab === id ? '2px solid var(--color-primary)' : '2px solid transparent',
              marginBottom: -1, display: 'flex', alignItems: 'center', gap: 6,
            }}
          >
            {label}
            {count > 0 && (
              <span style={{
                background: tab === id ? 'var(--color-primary)' : '#e5e7eb',
                color: tab === id ? '#fff' : '#6b7280',
                borderRadius: '100px', padding: '1px 7px', fontSize: 11, fontWeight: 700,
              }}>{count}</span>
            )}
          </button>
        ))}
      </div>

      {/* ── TAB: FALTAS ── */}
      {tab === 'faltas' && (
        <div>
          <FilterBar>
            <select
              value={periodoFaltas}
              onChange={(e) => setPeriodoFaltas(Number(e.target.value))}
              style={selectStyle}
            >
              {PERIODO_OPTIONS.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
            </select>
            <select
              value={profFiltro}
              onChange={(e) => setProfFiltro(e.target.value)}
              style={selectStyle}
            >
              <option value="">Todos os profissionais</option>
              {equipe.filter((m) => m.ativo).map((m) => <option key={m.id} value={m.nome}>{m.nome}</option>)}
            </select>
            <SearchInput value={buscaFaltas} onChange={setBuscaFaltas} placeholder="Buscar cliente..." />
            <button onClick={loadFaltas} style={refreshBtn}><RefreshCw size={14} /></button>
          </FilterBar>

          {selectedFaltas.size > 0 && (
            <BulkBar count={selectedFaltas.size} onSend={handleBulkFaltas} onClear={() => setSelectedFaltas(new Set())} />
          )}

          {loadingFaltas ? (
            <EmptyState icon={<AlertTriangle size={32} />} text="Carregando faltas..." />
          ) : faltasFiltradas.length === 0 ? (
            <EmptyState icon={<AlertTriangle size={32} />} text={`Nenhuma falta nos últimos ${periodoFaltas} dias.`} />
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
              {faltasFiltradas.map((f) => (
                <CRCCard
                  key={f.agendamentoId}
                  selected={selectedFaltas.has(f.agendamentoId)}
                  onToggleSelect={() => toggleFalta(f.agendamentoId)}
                >
                  <div style={{ flex: 1, minWidth: 160 }}>
                    <div style={{ fontWeight: 600, fontSize: 15, color: 'var(--color-text-main)' }}>{f.clienteNome}</div>
                    <div style={{ fontSize: 12, color: 'var(--color-text-muted)', marginTop: 2 }}>
                      {f.procedimento} · {f.profissional}
                      {f.faltaMotivo && <span style={{ marginLeft: 6, fontStyle: 'italic' }}>({f.faltaMotivo})</span>}
                    </div>
                  </div>
                  <div style={{ fontSize: 13, color: 'var(--color-text-muted)', minWidth: 90, textAlign: 'right' }}>
                    <div style={{ fontWeight: 600, color: '#C2410C' }}>{formatDate(f.data)}</div>
                    <div style={{ fontSize: 11 }}>{f.telefone || '—'}</div>
                  </div>
                  <div style={{ display: 'flex', gap: 6, flexShrink: 0 }}>
                    {f.telefone && (
                      <>
                        <ActionBtn title="WhatsApp" color="#15803D" onClick={() => openMsgModal([{ clienteId: f.clienteId, nome: f.clienteNome, telefone: f.telefone }], 'falta', { procedimento: f.procedimento, data: formatDate(f.data) })}>
                          <MessageCircle size={15} />
                        </ActionBtn>
                        <ActionBtn title="Ligar" onClick={async () => {
                          window.open(`tel:${f.telefone}`);
                          await api.registrarCrcAcao({ clienteId: f.clienteId, tipo: 'ligacao', contexto: 'falta', usuarioNome: userName }, userId).catch(() => {});
                        }}>
                          <Phone size={15} />
                        </ActionBtn>
                      </>
                    )}
                    {onAgendar && (
                      <ActionBtn title="Reagendar" color="#1D4ED8" onClick={async () => {
                        await api.registrarCrcAcao({ clienteId: f.clienteId, tipo: 'reagendamento', contexto: 'falta', usuarioNome: userName }, userId).catch(() => {});
                        onAgendar();
                      }}>
                        <CalendarRange size={15} />
                      </ActionBtn>
                    )}
                  </div>
                </CRCCard>
              ))}
            </div>
          )}
        </div>
      )}

      {/* ── TAB: INADIMPLENTES ── */}
      {tab === 'inadimplentes' && (
        <div>
          <FilterBar>
            <SearchInput value={buscaInadimpl} onChange={setBuscaInadimpl} placeholder="Buscar cliente..." />
            <button onClick={loadInadimpl} style={refreshBtn}><RefreshCw size={14} /></button>
            {pode('criar') && (
              <button
                onClick={() => { setContaForm(EMPTY_CONTA); setClienteBusca(''); setShowContaModal(true); }}
                style={{ display: 'flex', alignItems: 'center', gap: 6, background: 'var(--color-primary)', color: '#fff', border: 'none', borderRadius: 'var(--border-radius-md)', padding: '8px 14px', fontSize: 13, fontWeight: 600, cursor: 'pointer' }}
              >
                <Plus size={14} /> Registrar conta
              </button>
            )}
          </FilterBar>

          {selectedInadimpl.size > 0 && (
            <BulkBar count={selectedInadimpl.size} onSend={handleBulkInadimpl} onClear={() => setSelectedInadimpl(new Set())} label="Cobrar" />
          )}

          {loadingInadimpl ? (
            <EmptyState icon={<TrendingDown size={32} />} text="Carregando inadimplentes..." />
          ) : inadimplFiltrados.length === 0 ? (
            <EmptyState icon={<TrendingDown size={32} />} text="Nenhum inadimplente encontrado." />
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
              {inadimplFiltrados.map((c) => (
                <CRCCard
                  key={c.id}
                  selected={selectedInadimpl.has(c.id)}
                  onToggleSelect={() => toggleInadimpl(c.id)}
                >
                  <div style={{ flex: 1, minWidth: 160 }}>
                    <div style={{ fontWeight: 600, fontSize: 15, color: 'var(--color-text-main)' }}>{c.clienteNome}</div>
                    <div style={{ fontSize: 12, color: 'var(--color-text-muted)', marginTop: 2 }}>{c.descricao}</div>
                  </div>
                  <div style={{ minWidth: 100, textAlign: 'right' }}>
                    <div style={{ fontWeight: 700, fontSize: 16, color: '#B91C1C' }}>{formatCurrency(c.valor)}</div>
                    <div style={{ fontSize: 11, color: 'var(--color-text-muted)' }}>Venceu {formatDate(c.dataVencimento)}</div>
                    {c.diasAtraso > 0 && (
                      <div style={{ fontSize: 11, color: '#B91C1C', fontWeight: 600 }}>{c.diasAtraso}d em atraso</div>
                    )}
                  </div>
                  <div style={{ fontSize: 12, color: 'var(--color-text-muted)', minWidth: 80 }}>{c.telefone || '—'}</div>
                  <div style={{ display: 'flex', gap: 6, flexShrink: 0 }}>
                    {c.telefone && (
                      <ActionBtn title="Lembrete WhatsApp" color="#15803D" onClick={() => openMsgModal([{ clienteId: c.clienteId, nome: c.clienteNome, telefone: c.telefone }], 'inadimplente', { valor: formatCurrency(c.valor), vencimento: formatDate(c.dataVencimento) })}>
                        <MessageCircle size={15} />
                      </ActionBtn>
                    )}
                    {pode('editar') && (
                      <ActionBtn title="Marcar como pago" color="#15803D" onClick={() => handleMarcarPago(c)}>
                        <CheckCircle2 size={15} />
                      </ActionBtn>
                    )}
                    {pode('deletar') && (
                      <ActionBtn title="Excluir" color="#B91C1C" onClick={() => handleDeleteConta(c.id)}>
                        <Trash2 size={15} />
                      </ActionBtn>
                    )}
                  </div>
                </CRCCard>
              ))}
            </div>
          )}
        </div>
      )}

      {/* ── TAB: SEM REAGENDAMENTO ── */}
      {tab === 'sem_retorno' && (
        <div>
          <FilterBar>
            <select
              value={periodoSemRetorno}
              onChange={(e) => setPeriodoSemRetorno(Number(e.target.value))}
              style={selectStyle}
            >
              {SEM_RETORNO_OPCOES.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
            </select>
            <SearchInput value={buscaSemRetorno} onChange={setBuscaSemRetorno} placeholder="Buscar cliente..." />
            <button onClick={loadSemRetorno} style={refreshBtn}><RefreshCw size={14} /></button>
          </FilterBar>

          {selectedSemRet.size > 0 && (
            <BulkBar count={selectedSemRet.size} onSend={handleBulkSemRetorno} onClear={() => setSelectedSemRet(new Set())} label="Contatar" />
          )}

          {loadingSemRetorno ? (
            <EmptyState icon={<Users size={32} />} text="Carregando pacientes..." />
          ) : semRetornoFiltrados.length === 0 ? (
            <EmptyState icon={<Users size={32} />} text={`Nenhum paciente sem retorno há ${periodoSemRetorno}+ dias.`} />
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
              {semRetornoFiltrados.map((s) => (
                <CRCCard
                  key={s.clienteId}
                  selected={selectedSemRet.has(s.clienteId)}
                  onToggleSelect={() => toggleSemRet(s.clienteId)}
                >
                  <div style={{ flex: 1, minWidth: 160 }}>
                    <div style={{ fontWeight: 600, fontSize: 15, color: 'var(--color-text-main)' }}>{s.clienteNome}</div>
                    <div style={{ fontSize: 12, color: 'var(--color-text-muted)', marginTop: 2 }}>
                      {s.ultimoProcedimento || 'Procedimento desconhecido'}
                      {s.profissional && ` · ${s.profissional}`}
                    </div>
                  </div>
                  <div style={{ minWidth: 110, textAlign: 'right' }}>
                    <div style={{ fontWeight: 600, color: '#1D4ED8', fontSize: 15 }}>{s.diasSemVisita}d sem visita</div>
                    <div style={{ fontSize: 11, color: 'var(--color-text-muted)' }}>Última: {formatDate(s.dataUltimaVisita)}</div>
                    <div style={{ fontSize: 11, color: 'var(--color-text-muted)' }}>{s.telefone || '—'}</div>
                  </div>
                  <div style={{ display: 'flex', gap: 6, flexShrink: 0 }}>
                    {s.telefone && (
                      <>
                        <ActionBtn title="WhatsApp" color="#15803D" onClick={() => openMsgModal([{ clienteId: s.clienteId, nome: s.clienteNome, telefone: s.telefone }], 'sem_reagendamento', { procedimento: s.ultimoProcedimento })}>
                          <MessageCircle size={15} />
                        </ActionBtn>
                        <ActionBtn title="Ligar" onClick={async () => {
                          window.open(`tel:${s.telefone}`);
                          await api.registrarCrcAcao({ clienteId: s.clienteId, tipo: 'ligacao', contexto: 'sem_reagendamento', usuarioNome: userName }, userId).catch(() => {});
                        }}>
                          <Phone size={15} />
                        </ActionBtn>
                      </>
                    )}
                    {onAgendar && (
                      <ActionBtn title="Reagendar" color="#1D4ED8" onClick={async () => {
                        await api.registrarCrcAcao({ clienteId: s.clienteId, tipo: 'reagendamento', contexto: 'sem_reagendamento', usuarioNome: userName }, userId).catch(() => {});
                        onAgendar();
                      }}>
                        <CalendarRange size={15} />
                      </ActionBtn>
                    )}
                    {pode('editar') && (
                      <ActionBtn title="Não retorna mais" color="#6B7280" onClick={() => handleNaoRetorna(s)}>
                        <UserX size={15} />
                      </ActionBtn>
                    )}
                  </div>
                </CRCCard>
              ))}
            </div>
          )}
        </div>
      )}

      {/* ── MODAL: MENSAGEM ── */}
      {showMsgModal && (
        <Modal
          title={msgRecipients.length === 1 ? `Mensagem para ${msgRecipients[0].nome}` : `Mensagem em lote (${msgRecipients.length} pacientes)`}
          onClose={() => setShowMsgModal(false)}
          width={520}
        >
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            {templates.length > 0 && (
              <div>
                <Label>Template</Label>
                <select value={templateId} onChange={(e) => handleTemplateChange(e.target.value)} style={inputStyle}>
                  <option value="">Selecionar template...</option>
                  {templates.map((t) => <option key={t.id} value={t.id}>{t.titulo}</option>)}
                </select>
              </div>
            )}
            <div>
              <Label>Mensagem</Label>
              <textarea
                value={msgText}
                onChange={(e) => setMsgText(e.target.value)}
                rows={5}
                placeholder="Digite a mensagem..."
                style={{ ...inputStyle, resize: 'vertical' }}
              />
              {msgRecipients.length > 1 && (
                <p style={{ fontSize: 11, color: 'var(--color-text-muted)', margin: '4px 0 0' }}>
                  A mensagem será personalizada com o nome de cada paciente se usar {'{{nome}}'}.
                </p>
              )}
            </div>

            {msgRecipients.length > 0 && !msgRecipients[0].telefone && (
              <div style={{ background: '#FEF2F2', border: '1px solid #FECACA', borderRadius: 8, padding: '10px 14px', fontSize: 13, color: '#B91C1C' }}>
                Atenção: alguns pacientes não têm telefone cadastrado e não receberão a mensagem.
              </div>
            )}

            <div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end', paddingTop: 4 }}>
              <button onClick={() => setShowMsgModal(false)} style={btnSecondary}>Cancelar</button>
              <button onClick={handleEnviarMensagem} disabled={saving} style={btnPrimary}>
                {saving ? 'Abrindo...' : `Abrir WhatsApp${msgRecipients.length > 1 ? ` (${msgRecipients.length})` : ''}`}
              </button>
            </div>
          </div>
        </Modal>
      )}

      {/* ── MODAL: NOVA CONTA ── */}
      {showContaModal && (
        <Modal title="Registrar Conta a Receber" onClose={() => setShowContaModal(false)} width={460}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
            <div style={{ position: 'relative' }}>
              <Label>Cliente *</Label>
              <input
                value={clienteBusca || contaForm.clienteNome}
                onChange={(e) => {
                  setClienteBusca(e.target.value);
                  setContaForm((f) => ({ ...f, clienteNome: e.target.value, clienteId: '' }));
                }}
                placeholder="Buscar cliente..."
                style={inputStyle}
              />
              {clienteSugestoes.length > 0 && (
                <div style={{ position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 100, background: 'var(--bg-card)', border: '1px solid var(--color-border)', borderRadius: 'var(--border-radius-md)', boxShadow: '0 8px 24px rgba(0,0,0,.08)', overflow: 'hidden' }}>
                  {clienteSugestoes.map((c) => (
                    <button key={c.id} onClick={() => { setContaForm((f) => ({ ...f, clienteId: c.id, clienteNome: c.nome })); setClienteBusca(''); setClienteSugestoes([]); }}
                      style={{ width: '100%', textAlign: 'left', padding: '10px 14px', background: 'transparent', border: 'none', cursor: 'pointer', fontSize: 14, borderBottom: '1px solid var(--color-border)', color: 'var(--color-text-main)' }}>
                      {c.nome}
                    </button>
                  ))}
                </div>
              )}
            </div>
            <div>
              <Label>Descrição *</Label>
              <input value={contaForm.descricao} onChange={(e) => setContaForm((f) => ({ ...f, descricao: e.target.value }))} placeholder="Ex: Botox sessão 2" style={inputStyle} />
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
              <div>
                <Label>Valor (R$) *</Label>
                <input type="number" min={0} step={0.01} value={contaForm.valor || ''} onChange={(e) => setContaForm((f) => ({ ...f, valor: Number(e.target.value) }))} placeholder="0,00" style={inputStyle} />
              </div>
              <div>
                <Label>Vencimento *</Label>
                <input type="date" value={contaForm.dataVencimento} onChange={(e) => setContaForm((f) => ({ ...f, dataVencimento: e.target.value }))} style={inputStyle} />
              </div>
            </div>
            <div>
              <Label>Observações</Label>
              <input value={contaForm.observacoes} onChange={(e) => setContaForm((f) => ({ ...f, observacoes: e.target.value }))} placeholder="Opcional..." style={inputStyle} />
            </div>
            <div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end', paddingTop: 4 }}>
              <button onClick={() => setShowContaModal(false)} style={btnSecondary}>Cancelar</button>
              <button onClick={handleSaveConta} disabled={saving} style={btnPrimary}>
                {saving ? 'Salvando...' : 'Salvar'}
              </button>
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
};

// ── Sub-componentes ────────────────────────────────────────────────────────

function SummaryChip({ icon, label, value, color, bg, border, onClick }: {
  icon: React.ReactNode; label: string; value: number;
  color: string; bg: string; border: string; onClick: () => void;
}) {
  return (
    <button
      onClick={onClick}
      style={{
        display: 'flex', alignItems: 'center', gap: 10, padding: '10px 16px',
        background: bg, border: `1px solid ${border}`, borderRadius: 'var(--border-radius-md)',
        cursor: 'pointer', color,
      }}
    >
      {icon}
      <div style={{ textAlign: 'left' }}>
        <div style={{ fontSize: 11, fontWeight: 500, opacity: 0.8 }}>{label}</div>
        <div style={{ fontSize: 20, fontWeight: 700, lineHeight: 1 }}>{value}</div>
      </div>
    </button>
  );
}

function FilterBar({ children }: { children: React.ReactNode }) {
  return (
    <div style={{ display: 'flex', gap: 10, alignItems: 'center', marginBottom: 14, flexWrap: 'wrap' }}>
      {children}
    </div>
  );
}

function SearchInput({ value, onChange, placeholder }: { value: string; onChange: (v: string) => void; placeholder: string }) {
  return (
    <div style={{ position: 'relative', flex: 1, minWidth: 160, maxWidth: 280 }}>
      <Search size={14} style={{ position: 'absolute', left: 10, top: '50%', transform: 'translateY(-50%)', color: 'var(--color-text-muted)' }} />
      <input value={value} onChange={(e) => onChange(e.target.value)} placeholder={placeholder}
        style={{ ...inputStyle, paddingLeft: 30, width: '100%', boxSizing: 'border-box' }} />
    </div>
  );
}

function BulkBar({ count, onSend, onClear, label = 'Enviar mensagem' }: {
  count: number; onSend: () => void; onClear: () => void; label?: string;
}) {
  return (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 12, padding: '10px 16px', marginBottom: 12,
      background: 'var(--color-primary-light)', border: '1px solid var(--color-border-hover)',
      borderRadius: 'var(--border-radius-md)',
    }}>
      <span style={{ fontSize: 13, fontWeight: 600, color: 'var(--color-primary)' }}>{count} selecionado{count > 1 ? 's' : ''}</span>
      <button onClick={onSend} style={{ display: 'flex', alignItems: 'center', gap: 6, background: 'var(--color-primary)', color: '#fff', border: 'none', borderRadius: 'var(--border-radius-sm)', padding: '6px 14px', fontSize: 13, fontWeight: 600, cursor: 'pointer' }}>
        <MessageCircle size={14} /> {label} ({count})
      </button>
      <button onClick={onClear} style={{ background: 'none', border: 'none', color: 'var(--color-text-muted)', cursor: 'pointer', padding: 4 }}>
        <X size={14} />
      </button>
    </div>
  );
}

function CRCCard({ children, selected, onToggleSelect }: {
  children: React.ReactNode; selected: boolean; onToggleSelect: () => void;
}) {
  return (
    <div style={{
      background: 'var(--bg-card)',
      border: `1px solid ${selected ? 'var(--color-primary)' : 'var(--color-border)'}`,
      borderRadius: 'var(--border-radius-md)', padding: '14px 16px',
      display: 'flex', alignItems: 'center', gap: 12,
      transition: 'var(--transition-smooth)',
    }}>
      <input type="checkbox" checked={selected} onChange={onToggleSelect}
        style={{ width: 16, height: 16, accentColor: 'var(--color-primary)', flexShrink: 0, cursor: 'pointer' }} />
      {children}
    </div>
  );
}

function EmptyState({ icon, text }: { icon: React.ReactNode; text: string }) {
  return (
    <div style={{ textAlign: 'center', padding: '48px 0', color: 'var(--color-text-muted)', fontSize: 14 }}>
      <div style={{ opacity: 0.3, marginBottom: 12 }}>{icon}</div>
      {text}
    </div>
  );
}

function ActionBtn({ children, title, color, onClick }: {
  children: React.ReactNode; title?: string; color?: string; onClick: () => void;
}) {
  return (
    <button title={title} onClick={onClick} style={{
      width: 32, height: 32, display: 'flex', alignItems: 'center', justifyContent: 'center',
      background: 'transparent', border: '1px solid var(--color-border)',
      borderRadius: 'var(--border-radius-sm)', cursor: 'pointer', color: color ?? 'var(--color-text-muted)',
      transition: 'var(--transition-smooth)',
    }}
      onMouseEnter={(e) => { e.currentTarget.style.background = 'var(--color-primary-light)'; }}
      onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; }}
    >
      {children}
    </button>
  );
}

function Modal({ title, onClose, children, width = 500 }: {
  title: string; onClose: () => void; children: React.ReactNode; width?: number;
}) {
  useEffect(() => {
    const h = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    document.addEventListener('keydown', h);
    return () => document.removeEventListener('keydown', h);
  }, [onClose]);
  return (
    <div className="modal-overlay" style={{ position: 'fixed', inset: 0, zIndex: 1000, background: 'rgba(0,0,0,.45)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16 }}
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="modal-inner" style={{ background: 'var(--bg-card)', borderRadius: 'var(--border-radius-lg)', boxShadow: '0 20px 60px rgba(0,0,0,.15)', width: '100%', maxWidth: width, maxHeight: '90vh', overflowY: 'auto', padding: '24px' }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 20 }}>
          <h2 style={{ margin: 0, fontSize: 17, fontWeight: 700 }}>{title}</h2>
          <button onClick={onClose} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--color-text-muted)', display: 'flex', padding: 4 }}><X size={20} /></button>
        </div>
        {children}
      </div>
    </div>
  );
}

function Label({ children }: { children: React.ReactNode }) {
  return <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--color-text-muted)', marginBottom: 5, textTransform: 'uppercase', letterSpacing: '.04em' }}>{children}</div>;
}

const inputStyle: React.CSSProperties = {
  width: '100%', padding: '9px 12px', border: '1px solid var(--color-border)',
  borderRadius: 'var(--border-radius-md)', fontSize: 14, background: 'var(--bg-card)',
  color: 'var(--color-text-main)', outline: 'none', boxSizing: 'border-box',
};

const selectStyle: React.CSSProperties = {
  ...inputStyle, width: 'auto', minWidth: 140,
};

const refreshBtn: React.CSSProperties = {
  display: 'flex', alignItems: 'center', justifyContent: 'center',
  width: 34, height: 34, background: 'transparent', border: '1px solid var(--color-border)',
  borderRadius: 'var(--border-radius-md)', cursor: 'pointer', color: 'var(--color-text-muted)',
};

const btnPrimary: React.CSSProperties = {
  background: 'var(--color-primary)', color: '#fff', border: 'none',
  borderRadius: 'var(--border-radius-md)', padding: '10px 20px', fontSize: 14, fontWeight: 600, cursor: 'pointer',
};

const btnSecondary: React.CSSProperties = {
  background: 'transparent', color: 'var(--color-text-main)', border: '1px solid var(--color-border)',
  borderRadius: 'var(--border-radius-md)', padding: '10px 20px', fontSize: 14, fontWeight: 500, cursor: 'pointer',
};

import React, { useCallback, useEffect, useRef, useState } from 'react';
import {
  Plus, X, BarChart2, Settings2, Clock, AlertTriangle,
  ChevronRight, Zap, MessageSquare, Mail, CheckSquare,
  MoreHorizontal, User, Phone, Globe, Trash2, Edit3,
  ArrowRightCircle, History, FileText, Tag, Users,
} from 'lucide-react';
import { api } from '../lib/api';
import type {
  FunilEtapa, FunilEtapaTipo, Lead, LeadAutomacao, LeadHistorico, LeadOrigem,
} from '../types';
import { RankingPacientes } from './RankingPacientes';

// ── Utilitários ───────────────────────────────────────────────────────

function diasDesde(iso: string): number {
  return Math.floor((Date.now() - new Date(iso).getTime()) / (1000 * 60 * 60 * 24));
}

function formatData(iso: string): string {
  return new Date(iso).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: '2-digit' });
}

const ORIGENS: { value: LeadOrigem; label: string }[] = [
  { value: 'instagram', label: 'Instagram' },
  { value: 'google',    label: 'Google' },
  { value: 'indicacao', label: 'Indicação' },
  { value: 'whatsapp',  label: 'WhatsApp' },
  { value: 'tiktok',    label: 'TikTok' },
  { value: 'outro',     label: 'Outro' },
];

const ORIGEM_LABELS: Record<LeadOrigem, string> = {
  instagram: 'Instagram', google: 'Google', indicacao: 'Indicação',
  whatsapp: 'WhatsApp', tiktok: 'TikTok', outro: 'Outro',
};

const TIPO_COR: Record<FunilEtapaTipo, string> = {
  ativo:      'var(--color-primary)',
  convertido: '#10B981',
  perdido:    '#EF4444',
};

// ── Props ─────────────────────────────────────────────────────────────

interface CRMProps {
  userId: string;
  userName: string;
  onConvertidoAgendar?: (clienteId: string, clienteNome: string) => void;
  permissoes?: import('../types').Permissoes | null;
}

// ── Estado inicial do formulário de lead ─────────────────────────────

const LEAD_VAZIO = {
  nome: '', telefone: '', email: '',
  procedimentoInteresse: '', origem: 'outro' as LeadOrigem, observacoes: '',
};

// ═══════════════════════════════════════════════════════════════════════
// COMPONENTE PRINCIPAL
// ═══════════════════════════════════════════════════════════════════════

export const CRM: React.FC<CRMProps> = ({ userId, userName, onConvertidoAgendar, permissoes }) => {
  const pode = (acao: 'ver' | 'criar' | 'editar' | 'deletar') =>
    !permissoes || !!(permissoes['crm']?.[acao]);
  const [activeView, setActiveView] = useState<'pipeline' | 'ranking'>('pipeline');

  const [etapas, setEtapas]     = useState<FunilEtapa[]>([]);
  const [leads, setLeads]       = useState<Lead[]>([]);
  const [loading, setLoading]   = useState(true);

  // DnD
  const [dragLeadId, setDragLeadId]       = useState<string | null>(null);
  const [dragOverEtapa, setDragOverEtapa] = useState<string | null>(null);

  // Touch DnD
  const touchLeadGhostRef   = useRef<HTMLDivElement>(null);
  const touchActiveLeadRef  = useRef<{ id: string } | null>(null);
  const [touchLeadGhostPos, setTouchLeadGhostPos]     = useState<{ x: number; y: number } | null>(null);
  const [touchLeadGhostLabel, setTouchLeadGhostLabel] = useState('');

  // Modais
  const [leadModal, setLeadModal]         = useState<{ open: boolean; lead?: Lead; etapaId?: string }>({ open: false });
  const [detalheModal, setDetalheModal]   = useState<Lead | null>(null);
  const [historico, setHistorico]         = useState<LeadHistorico[]>([]);
  const [metricasOpen, setMetricasOpen]   = useState(false);
  const [etapasOpen, setEtapasOpen]       = useState(false);
  const [automacoesModal, setAutomacoesModal] = useState<FunilEtapa | null>(null);
  const [convertDialog, setConvertDialog] = useState<Lead | null>(null);

  // Notas
  const [novaNota, setNovaNota] = useState('');
  const [savingNota, setSavingNota] = useState(false);

  // Conversão
  const [convertendo, setConvertendo] = useState(false);

  // ── Carga de dados ─────────────────────────────────────────────────

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const [e, l] = await Promise.all([
        api.initFunilPadrao(userId),
        api.getLeads(userId),
      ]);
      setEtapas(e);
      setLeads(l);
    } catch (err) {
      console.error('[CRM] Erro ao carregar:', err);
    } finally {
      setLoading(false);
    }
  }, [userId]);

  useEffect(() => { load(); }, [load]);

  // ── DnD handlers ───────────────────────────────────────────────────

  const handleDragStart = (leadId: string) => setDragLeadId(leadId);
  const handleDragEnd   = () => { setDragLeadId(null); setDragOverEtapa(null); };

  const handleDragOver = (e: React.DragEvent, etapaId: string) => {
    e.preventDefault();
    setDragOverEtapa(etapaId);
  };

  const handleDrop = async (e: React.DragEvent, etapaId: string) => {
    e.preventDefault();
    if (!dragLeadId || dragLeadId === etapaId) { handleDragEnd(); return; }
    const lead = leads.find((l) => l.id === dragLeadId);
    if (!lead || lead.etapaId === etapaId) { handleDragEnd(); return; }

    const etapaDestino = etapas.find((et) => et.id === etapaId);
    if (etapaDestino?.tipo === 'convertido') {
      setConvertDialog(lead);
      handleDragEnd();
      return;
    }

    // Atualização otimista
    setLeads((prev) => prev.map((l) =>
      l.id === dragLeadId ? { ...l, etapaId, etapaEntradaEm: new Date().toISOString() } : l
    ));
    handleDragEnd();

    try {
      await api.moverLead(dragLeadId, etapaId, userName, userId);
      await api.dispararAutomacoesEtapa(dragLeadId, etapaId, userName, userId);
    } catch (err) {
      console.error('[CRM] Erro ao mover lead:', err);
      load();
    }
  };

  // ── Touch DnD handlers ─────────────────────────────────────────────
  const handleTouchStartLead = (
    e: React.TouchEvent<HTMLDivElement>,
    leadId: string,
    nome: string
  ) => {
    const touch = e.touches[0];
    touchActiveLeadRef.current = { id: leadId };
    setTouchLeadGhostLabel(nome);
    setTouchLeadGhostPos({ x: touch.clientX, y: touch.clientY });
    setDragLeadId(leadId);
  };

  const handleTouchMoveLead = (e: React.TouchEvent<HTMLDivElement>) => {
    if (!touchActiveLeadRef.current) return;
    const touch = e.touches[0];
    setTouchLeadGhostPos({ x: touch.clientX, y: touch.clientY });
    const ghostEl = touchLeadGhostRef.current;
    if (ghostEl) ghostEl.style.display = 'none';
    const el = document.elementFromPoint(touch.clientX, touch.clientY);
    if (ghostEl) ghostEl.style.display = '';
    const col = el?.closest('[data-dnd-col]');
    const colId = col?.getAttribute('data-dnd-col') ?? null;
    setDragOverEtapa(colId);
  };

  const handleTouchEndLead = async () => {
    if (!touchActiveLeadRef.current) return;
    const leadId = touchActiveLeadRef.current.id;
    const etapaId = dragOverEtapa;
    touchActiveLeadRef.current = null;
    setTouchLeadGhostPos(null);
    setDragLeadId(null);
    setDragOverEtapa(null);
    if (!leadId || !etapaId) return;
    const lead = leads.find((l) => l.id === leadId);
    if (!lead || lead.etapaId === etapaId) return;
    const etapaDestino = etapas.find((et) => et.id === etapaId);
    if (etapaDestino?.tipo === 'convertido') {
      setConvertDialog(lead);
      return;
    }
    setLeads((prev) => prev.map((l) =>
      l.id === leadId ? { ...l, etapaId, etapaEntradaEm: new Date().toISOString() } : l
    ));
    try {
      await api.moverLead(leadId, etapaId, userName, userId);
      await api.dispararAutomacoesEtapa(leadId, etapaId, userName, userId);
    } catch (err) {
      console.error('[CRM] Erro ao mover lead (touch):', err);
      load();
    }
  };

  // ── Salvar lead (criar ou editar) ──────────────────────────────────

  const [savingLead, setSavingLead] = useState(false);
  const [leadForm, setLeadForm] = useState(LEAD_VAZIO);

  const abrirCriarLead = (etapaId: string) => {
    setLeadForm(LEAD_VAZIO);
    setLeadModal({ open: true, etapaId });
  };

  const abrirEditarLead = (lead: Lead) => {
    setLeadForm({
      nome: lead.nome, telefone: lead.telefone, email: lead.email,
      procedimentoInteresse: lead.procedimentoInteresse,
      origem: lead.origem, observacoes: lead.observacoes,
    });
    setLeadModal({ open: true, lead });
  };

  const salvarLead = async () => {
    if (!leadForm.nome.trim()) return;
    setSavingLead(true);
    try {
      if (leadModal.lead) {
        const atualizado = await api.updateLead(leadModal.lead.id, leadForm, userId);
        setLeads((prev) => prev.map((l) => l.id === atualizado.id ? atualizado : l));
      } else {
        const novo = await api.createLead({
          ...leadForm,
          etapaId: leadModal.etapaId ?? etapas[0]?.id ?? '',
          responsavelId: null, responsavelNome: null,
        }, userId);
        setLeads((prev) => [novo, ...prev]);
      }
      setLeadModal({ open: false });
    } catch (err) {
      console.error('[CRM] Erro ao salvar lead:', err);
      alert('Erro ao salvar lead. Tente novamente.');
    } finally {
      setSavingLead(false);
    }
  };

  // ── Excluir lead ───────────────────────────────────────────────────

  const excluirLead = async (lead: Lead) => {
    if (!confirm(`Excluir o lead "${lead.nome}"? Esta ação não pode ser desfeita.`)) return;
    try {
      await api.deleteLead(lead.id, userId);
      setLeads((prev) => prev.filter((l) => l.id !== lead.id));
      if (detalheModal?.id === lead.id) setDetalheModal(null);
    } catch (err) {
      console.error('[CRM] Erro ao excluir:', err);
      alert('Erro ao excluir lead.');
    }
  };

  // ── Detalhe + histórico ────────────────────────────────────────────

  const abrirDetalhe = async (lead: Lead) => {
    setDetalheModal(lead);
    setHistorico([]);
    try {
      const h = await api.getLeadHistorico(lead.id, userId);
      setHistorico(h);
    } catch (err) {
      console.error('[CRM] Erro ao carregar histórico:', err);
    }
  };

  const enviarNota = async () => {
    if (!novaNota.trim() || !detalheModal) return;
    setSavingNota(true);
    try {
      const h = await api.addLeadNota(detalheModal.id, novaNota, userName, userId);
      setHistorico((prev) => [h, ...prev]);
      setNovaNota('');
    } catch (err) {
      console.error('[CRM] Erro ao salvar nota:', err);
    } finally {
      setSavingNota(false);
    }
  };

  // ── Conversão para paciente (CA-05) ────────────────────────────────

  const confirmarConversao = async () => {
    if (!convertDialog) return;
    setConvertendo(true);
    try {
      const { lead: leadConvertido, clienteId } = await api.converterLeadEmPaciente(
        convertDialog.id, userName, userId
      );
      setLeads((prev) => prev.map((l) => l.id === leadConvertido.id ? leadConvertido : l));
      setConvertDialog(null);
      if (onConvertidoAgendar) {
        onConvertidoAgendar(clienteId, convertDialog.nome);
      } else {
        alert(`"${convertDialog.nome}" foi convertido em paciente com sucesso!`);
      }
    } catch (err) {
      console.error('[CRM] Erro ao converter lead:', err);
      alert('Erro ao converter lead em paciente.');
    } finally {
      setConvertendo(false);
    }
  };

  // ── Métricas (CA-06) ───────────────────────────────────────────────

  const [metricas, setMetricas] = useState<Awaited<ReturnType<typeof api.getFunilMetricas>> | null>(null);

  const abrirMetricas = async () => {
    const m = await api.getFunilMetricas(etapas, leads);
    setMetricas(m);
    setMetricasOpen(true);
  };

  // ── Render ─────────────────────────────────────────────────────────

  if (loading) {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '60vh', color: 'var(--color-text-muted)' }}>
        Carregando funil de leads...
      </div>
    );
  }

  const leadsPorEtapa = (etapaId: string) => leads.filter((l) => l.etapaId === etapaId);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', overflow: 'hidden' }}>

      {/* ── Cabeçalho ─────────────────────────────────────────────── */}
      <div style={{
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        padding: '20px 24px 16px', flexShrink: 0,
        borderBottom: '1px solid var(--color-border)',
        flexWrap: 'wrap', gap: '12px',
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          <div>
            <h1 style={{ margin: 0, fontSize: '20px', fontWeight: 700, color: 'var(--color-text-main)' }}>
              {activeView === 'pipeline' ? 'Pipeline de Leads' : 'Ranking de Pacientes'}
            </h1>
            <span style={{ fontSize: '13px', color: 'var(--color-text-muted)' }}>
              {activeView === 'pipeline'
                ? `${leads.length} lead${leads.length !== 1 ? 's' : ''} no funil`
                : 'Score por LTV, frequência e ticket médio'}
            </span>
          </div>
          {/* Tab switcher */}
          <div style={{ display: 'flex', gap: '4px', background: '#f8f8f6', border: '1px solid var(--color-border)', borderRadius: '10px', padding: '4px' }}>
            <button
              onClick={() => setActiveView('pipeline')}
              style={{ padding: '6px 14px', fontSize: '12px', fontWeight: 600, border: 'none', cursor: 'pointer', borderRadius: '7px', background: activeView === 'pipeline' ? 'var(--color-primary)' : 'transparent', color: activeView === 'pipeline' ? '#fff' : 'var(--color-text-muted)', transition: 'all 0.15s', display: 'flex', alignItems: 'center', gap: '5px' }}>
              <BarChart2 size={13} /> Pipeline
            </button>
            <button
              onClick={() => setActiveView('ranking')}
              style={{ padding: '6px 14px', fontSize: '12px', fontWeight: 600, border: 'none', cursor: 'pointer', borderRadius: '7px', background: activeView === 'ranking' ? 'var(--color-primary)' : 'transparent', color: activeView === 'ranking' ? '#fff' : 'var(--color-text-muted)', transition: 'all 0.15s', display: 'flex', alignItems: 'center', gap: '5px' }}>
              <Users size={13} /> Ranking de Pacientes
            </button>
          </div>
        </div>
        {activeView === 'pipeline' && (
          <div style={{ display: 'flex', gap: '8px' }}>
            <button onClick={abrirMetricas} className="btn-secondary" style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px' }}>
              <BarChart2 size={15} /> Métricas
            </button>
            <button onClick={() => setEtapasOpen(true)} className="btn-secondary" style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px' }}>
              <Settings2 size={15} /> Etapas
            </button>
            {pode('criar') && (
              <button onClick={() => abrirCriarLead(etapas[0]?.id ?? '')} className="btn-primary" style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px' }}>
                <Plus size={15} /> Novo Lead
              </button>
            )}
          </div>
        )}
      </div>

      {/* ── Ranking de Pacientes (US-016) ─────────────────────────── */}
      {activeView === 'ranking' && <RankingPacientes userId={userId} />}

      {/* ── Kanban ────────────────────────────────────────────────── */}
      {activeView === 'pipeline' && <div style={{
        flex: 1, overflowX: 'auto', overflowY: 'hidden',
        display: 'flex', gap: '12px', padding: '16px 24px',
      }}>
        {etapas.map((etapa) => {
          const etapaLeads = leadsPorEtapa(etapa.id);
          const isOver = dragOverEtapa === etapa.id;
          return (
            <div
              key={etapa.id}
              data-dnd-col={etapa.id}
              onDragOver={(e) => handleDragOver(e, etapa.id)}
              onDrop={(e) => handleDrop(e, etapa.id)}
              onDragLeave={() => setDragOverEtapa(null)}
              style={{
                width: '280px', minWidth: '280px', display: 'flex', flexDirection: 'column',
                background: isOver ? 'var(--color-primary-light)' : 'var(--color-bg-secondary, #F9FAFB)',
                border: `2px ${isOver ? 'dashed' : 'solid'} ${isOver ? etapa.cor : 'var(--color-border)'}`,
                borderRadius: '12px', transition: 'all 0.15s ease',
              }}
            >
              {/* Header da coluna */}
              <div style={{
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                padding: '12px 14px',
                borderBottom: `3px solid ${etapa.cor}`,
                borderRadius: '10px 10px 0 0',
              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: etapa.cor }} />
                  <span style={{ fontWeight: 600, fontSize: '13px', color: 'var(--color-text-main)' }}>
                    {etapa.nome}
                  </span>
                  <span style={{
                    background: etapa.cor + '22', color: etapa.cor,
                    fontSize: '11px', fontWeight: 700,
                    padding: '1px 7px', borderRadius: '100px',
                  }}>
                    {etapaLeads.length}
                  </span>
                </div>
                <div style={{ display: 'flex', gap: '4px' }}>
                  <button
                    onClick={() => setAutomacoesModal(etapa)}
                    title="Automações"
                    style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '2px', color: 'var(--color-text-muted)', borderRadius: '4px' }}
                    onMouseEnter={e => (e.currentTarget.style.color = etapa.cor)}
                    onMouseLeave={e => (e.currentTarget.style.color = 'var(--color-text-muted)')}
                  >
                    <Zap size={13} />
                  </button>
                  {etapa.tipo === 'ativo' && (
                    <button
                      onClick={() => abrirCriarLead(etapa.id)}
                      title="Adicionar lead"
                      style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '2px', color: 'var(--color-text-muted)', borderRadius: '4px' }}
                      onMouseEnter={e => (e.currentTarget.style.color = etapa.cor)}
                      onMouseLeave={e => (e.currentTarget.style.color = 'var(--color-text-muted)')}
                    >
                      <Plus size={13} />
                    </button>
                  )}
                </div>
              </div>

              {/* Cards */}
              <div style={{ flex: 1, overflowY: 'auto', padding: '10px', display: 'flex', flexDirection: 'column', gap: '8px' }}>
                {etapaLeads.map((lead) => (
                  <LeadCard
                    key={lead.id}
                    lead={lead}
                    etapa={etapa}
                    isDragging={dragLeadId === lead.id}
                    onDragStart={() => handleDragStart(lead.id)}
                    onDragEnd={handleDragEnd}
                    onTouchStart={(e) => handleTouchStartLead(e, lead.id, lead.nome)}
                    onTouchMove={handleTouchMoveLead}
                    onTouchEnd={handleTouchEndLead}
                    onDetalhes={() => abrirDetalhe(lead)}
                    onEditar={() => abrirEditarLead(lead)}
                    onExcluir={() => excluirLead(lead)}
                    onConverter={() => setConvertDialog(lead)}
                  />
                ))}

                {etapaLeads.length === 0 && (
                  <div style={{
                    textAlign: 'center', padding: '20px 8px',
                    color: 'var(--color-text-muted)', fontSize: '12px',
                    border: '1px dashed var(--color-border)', borderRadius: '8px',
                  }}>
                    Nenhum lead nesta etapa
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>}

      {/* ── Modal: Criar/Editar Lead (CA-02) ───────────────────────── */}
      {leadModal.open && (
        <ModalOverlay onClose={() => setLeadModal({ open: false })}>
          <div style={{ width: '460px', maxWidth: '100%' }}>
            <ModalHeader
              title={leadModal.lead ? 'Editar Lead' : 'Novo Lead'}
              onClose={() => setLeadModal({ open: false })}
            />
            <div style={{ padding: '20px', display: 'flex', flexDirection: 'column', gap: '14px' }}>
              <div className="form-group">
                <label className="form-label">Nome *</label>
                <input
                  className="form-input"
                  value={leadForm.nome}
                  onChange={(e) => setLeadForm((f) => ({ ...f, nome: e.target.value }))}
                  placeholder="Ex: Maria Silva"
                  autoFocus
                />
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div className="form-group">
                  <label className="form-label">Telefone</label>
                  <input
                    className="form-input"
                    value={leadForm.telefone}
                    onChange={(e) => setLeadForm((f) => ({ ...f, telefone: e.target.value }))}
                    placeholder="(11) 99999-9999"
                  />
                </div>
                <div className="form-group">
                  <label className="form-label">E-mail</label>
                  <input
                    className="form-input"
                    type="email"
                    value={leadForm.email}
                    onChange={(e) => setLeadForm((f) => ({ ...f, email: e.target.value }))}
                    placeholder="contato@email.com"
                  />
                </div>
              </div>
              <div className="form-group">
                <label className="form-label">Procedimento de interesse</label>
                <input
                  className="form-input"
                  value={leadForm.procedimentoInteresse}
                  onChange={(e) => setLeadForm((f) => ({ ...f, procedimentoInteresse: e.target.value }))}
                  placeholder="Ex: Botox, Laser CO2, Harmonização..."
                />
              </div>
              <div className="form-group">
                <label className="form-label">Origem</label>
                <select
                  className="form-input"
                  value={leadForm.origem}
                  onChange={(e) => setLeadForm((f) => ({ ...f, origem: e.target.value as LeadOrigem }))}
                >
                  {ORIGENS.map((o) => (
                    <option key={o.value} value={o.value}>{o.label}</option>
                  ))}
                </select>
              </div>
              {!leadModal.lead && (
                <div className="form-group">
                  <label className="form-label">Etapa inicial</label>
                  <select
                    className="form-input"
                    value={leadModal.etapaId ?? etapas[0]?.id ?? ''}
                    onChange={(e) => setLeadModal((m) => ({ ...m, etapaId: e.target.value }))}
                  >
                    {etapas.filter((et) => et.tipo === 'ativo').map((et) => (
                      <option key={et.id} value={et.id}>{et.nome}</option>
                    ))}
                  </select>
                </div>
              )}
              <div className="form-group">
                <label className="form-label">Observações</label>
                <textarea
                  className="form-input"
                  value={leadForm.observacoes}
                  onChange={(e) => setLeadForm((f) => ({ ...f, observacoes: e.target.value }))}
                  placeholder="Informações adicionais sobre o contato..."
                  rows={3}
                  style={{ resize: 'vertical' }}
                />
              </div>
              <div style={{ display: 'flex', gap: '8px', justifyContent: 'flex-end', paddingTop: '4px' }}>
                <button className="btn-secondary" onClick={() => setLeadModal({ open: false })}>Cancelar</button>
                <button
                  className="btn-primary"
                  onClick={salvarLead}
                  disabled={savingLead || !leadForm.nome.trim()}
                >
                  {savingLead ? 'Salvando...' : leadModal.lead ? 'Salvar' : 'Criar Lead'}
                </button>
              </div>
            </div>
          </div>
        </ModalOverlay>
      )}

      {/* ── Modal: Detalhe + Histórico (CA-03) ─────────────────────── */}
      {detalheModal && (
        <ModalOverlay onClose={() => setDetalheModal(null)}>
          <div style={{ width: '520px', maxWidth: '100%', maxHeight: '90vh', display: 'flex', flexDirection: 'column' }}>
            <ModalHeader
              title={detalheModal.nome}
              onClose={() => setDetalheModal(null)}
            />
            <div style={{ flex: 1, overflowY: 'auto', padding: '20px', display: 'flex', flexDirection: 'column', gap: '16px' }}>
              {/* Info do lead */}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <InfoItem icon={<Phone size={13} />} label="Telefone" value={detalheModal.telefone || '—'} />
                <InfoItem icon={<Mail size={13} />}  label="E-mail"   value={detalheModal.email || '—'} />
                <InfoItem icon={<Tag size={13} />}   label="Procedimento" value={detalheModal.procedimentoInteresse || '—'} />
                <InfoItem icon={<Globe size={13} />} label="Origem"   value={ORIGEM_LABELS[detalheModal.origem]} />
                <InfoItem icon={<Clock size={13} />} label="Entrada"  value={formatData(detalheModal.createdAt)} />
                <InfoItem
                  icon={<AlertTriangle size={13} />}
                  label="Dias na etapa"
                  value={`${diasDesde(detalheModal.etapaEntradaEm)} dia(s)`}
                />
              </div>
              {detalheModal.observacoes && (
                <div style={{ background: 'var(--color-bg-secondary, #F9FAFB)', borderRadius: '8px', padding: '10px 12px' }}>
                  <span style={{ fontSize: '12px', color: 'var(--color-text-muted)', display: 'block', marginBottom: '4px' }}>Observações</span>
                  <span style={{ fontSize: '13px' }}>{detalheModal.observacoes}</span>
                </div>
              )}

              {/* Adicionar nota */}
              <div>
                <label className="form-label" style={{ marginBottom: '6px', display: 'block' }}>Adicionar nota</label>
                <div style={{ display: 'flex', gap: '8px' }}>
                  <input
                    className="form-input"
                    value={novaNota}
                    onChange={(e) => setNovaNota(e.target.value)}
                    placeholder="Registre uma observação..."
                    onKeyDown={(e) => e.key === 'Enter' && enviarNota()}
                    style={{ flex: 1 }}
                  />
                  <button
                    className="btn-primary"
                    onClick={enviarNota}
                    disabled={savingNota || !novaNota.trim()}
                    style={{ whiteSpace: 'nowrap' }}
                  >
                    Salvar
                  </button>
                </div>
              </div>

              {/* Histórico */}
              <div>
                <h3 style={{ margin: '0 0 10px', fontSize: '13px', fontWeight: 600, color: 'var(--color-text-main)' }}>
                  Histórico ({historico.length})
                </h3>
                {historico.length === 0 ? (
                  <p style={{ fontSize: '13px', color: 'var(--color-text-muted)' }}>Sem movimentações registradas.</p>
                ) : (
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                    {historico.map((h) => (
                      <HistoricoItem key={h.id} item={h} etapas={etapas} />
                    ))}
                  </div>
                )}
              </div>

              {/* Ações */}
              <div style={{ display: 'flex', gap: '8px', paddingTop: '4px', borderTop: '1px solid var(--color-border)' }}>
                <button className="btn-secondary" onClick={() => { setDetalheModal(null); abrirEditarLead(detalheModal); }} style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px' }}>
                  <Edit3 size={13} /> Editar
                </button>
                {!detalheModal.clienteId && (
                  <button
                    onClick={() => { setDetalheModal(null); setConvertDialog(detalheModal); }}
                    style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px', background: '#10B981', color: '#fff', border: 'none', borderRadius: '8px', padding: '8px 14px', cursor: 'pointer', fontWeight: 500 }}
                  >
                    <ArrowRightCircle size={13} /> Converter em Paciente
                  </button>
                )}
                <button className="btn-danger" onClick={() => { setDetalheModal(null); excluirLead(detalheModal); }} style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px', marginLeft: 'auto' }}>
                  <Trash2 size={13} /> Excluir
                </button>
              </div>
            </div>
          </div>
        </ModalOverlay>
      )}

      {/* ── Modal: Converter Lead (CA-05) ──────────────────────────── */}
      {convertDialog && (
        <ModalOverlay onClose={() => setConvertDialog(null)}>
          <div style={{ width: '400px', maxWidth: '100%', padding: '28px' }}>
            <div style={{ textAlign: 'center', marginBottom: '20px' }}>
              <div style={{ fontSize: '40px', marginBottom: '12px' }}>🎉</div>
              <h2 style={{ margin: '0 0 8px', fontSize: '18px', fontWeight: 700 }}>Converter em Paciente</h2>
              <p style={{ margin: 0, fontSize: '14px', color: 'var(--color-text-muted)', lineHeight: 1.5 }}>
                Deseja transformar <strong>{convertDialog.nome}</strong> em paciente e criar uma ficha no sistema?
              </p>
            </div>
            <div style={{ background: 'var(--color-primary-light)', borderRadius: '8px', padding: '12px', marginBottom: '20px', fontSize: '13px', color: 'var(--color-primary)' }}>
              Os dados do lead (nome, telefone, e-mail) serão usados para criar a ficha do paciente. Você poderá criar o agendamento em seguida.
            </div>
            <div style={{ display: 'flex', gap: '8px' }}>
              <button className="btn-secondary" onClick={() => setConvertDialog(null)} style={{ flex: 1 }}>Cancelar</button>
              <button
                onClick={confirmarConversao}
                disabled={convertendo}
                style={{ flex: 1, background: '#10B981', color: '#fff', border: 'none', borderRadius: '8px', padding: '10px', cursor: convertendo ? 'wait' : 'pointer', fontWeight: 600, fontSize: '14px' }}
              >
                {convertendo ? 'Convertendo...' : 'Confirmar Conversão'}
              </button>
            </div>
          </div>
        </ModalOverlay>
      )}

      {/* ── Modal: Métricas (CA-06) ─────────────────────────────────── */}
      {metricasOpen && metricas && (
        <ModalOverlay onClose={() => setMetricasOpen(false)}>
          <div style={{ width: '560px', maxWidth: '100%', maxHeight: '90vh', overflowY: 'auto' }}>
            <ModalHeader title="Métricas do Funil" onClose={() => setMetricasOpen(false)} />
            <div style={{ padding: '20px', display: 'flex', flexDirection: 'column', gap: '20px' }}>
              {/* Totais */}
              <div className="metricas-kpi-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '12px' }}>
                {[
                  { label: 'Total leads', value: metricas.totalLeads },
                  { label: 'Hoje',   value: metricas.leadsHoje },
                  { label: '7 dias', value: metricas.leadsSemana },
                  { label: '30 dias', value: metricas.leadsMes },
                ].map((m) => (
                  <div key={m.label} style={{ background: 'var(--color-primary-light)', borderRadius: '10px', padding: '14px', textAlign: 'center' }}>
                    <div style={{ fontSize: '24px', fontWeight: 700, color: 'var(--color-primary)' }}>{m.value}</div>
                    <div style={{ fontSize: '12px', color: 'var(--color-text-muted)', marginTop: '2px' }}>{m.label}</div>
                  </div>
                ))}
              </div>

              {/* Por etapa */}
              <div>
                <h3 style={{ margin: '0 0 10px', fontSize: '14px', fontWeight: 600 }}>Leads por etapa</h3>
                {etapas.map((et) => {
                  const count = metricas.leadsPorEtapa[et.id] ?? 0;
                  const pct = metricas.totalLeads > 0 ? Math.round((count / metricas.totalLeads) * 100) : 0;
                  return (
                    <div key={et.id} style={{ marginBottom: '8px' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '3px', fontSize: '13px' }}>
                        <span>{et.nome}</span>
                        <span style={{ fontWeight: 600 }}>{count} <span style={{ color: 'var(--color-text-muted)', fontWeight: 400 }}>({pct}%)</span></span>
                      </div>
                      <div style={{ background: 'var(--color-border)', borderRadius: '4px', height: '6px' }}>
                        <div style={{ background: et.cor, borderRadius: '4px', height: '6px', width: `${pct}%`, transition: 'width 0.3s' }} />
                      </div>
                    </div>
                  );
                })}
              </div>

              {/* Tempo médio por etapa */}
              <div>
                <h3 style={{ margin: '0 0 10px', fontSize: '14px', fontWeight: 600 }}>Tempo médio por etapa</h3>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                  {etapas.filter((et) => et.tipo === 'ativo').map((et) => (
                    <div key={et.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '8px 12px', background: 'var(--color-bg-secondary, #F9FAFB)', borderRadius: '8px', fontSize: '13px' }}>
                      <span>{et.nome}</span>
                      <span style={{ fontWeight: 600, color: 'var(--color-primary)' }}>
                        {metricas.tempoMedioPorEtapa[et.id] ?? 0} dias
                      </span>
                    </div>
                  ))}
                </div>
              </div>

              {/* Por origem */}
              <div>
                <h3 style={{ margin: '0 0 10px', fontSize: '14px', fontWeight: 600 }}>Leads por origem</h3>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                  {Object.entries(metricas.leadsPorOrigem).sort((a, b) => b[1] - a[1]).map(([origem, count]) => (
                    <div key={origem} style={{
                      background: 'var(--color-primary-light)', color: 'var(--color-primary)',
                      borderRadius: '100px', padding: '4px 12px', fontSize: '13px', fontWeight: 500,
                    }}>
                      {ORIGEM_LABELS[origem as LeadOrigem] ?? origem}: {count}
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </ModalOverlay>
      )}

      {/* ── Modal: Configurar Etapas ────────────────────────────────── */}
      {etapasOpen && (
        <EtapasConfigModal
          etapas={etapas}
          userId={userId}
          onClose={() => setEtapasOpen(false)}
          onSave={(e) => { setEtapas(e); setEtapasOpen(false); }}
        />
      )}

      {/* ── Modal: Automações por etapa (CA-04) ─────────────────────── */}
      {automacoesModal && (
        <AutomacoesModal
          etapa={automacoesModal}
          userId={userId}
          onClose={() => setAutomacoesModal(null)}
        />
      )}

      {/* Touch drag ghost */}
      {touchLeadGhostPos && (
        <div
          ref={touchLeadGhostRef}
          style={{
            position: 'fixed',
            left: touchLeadGhostPos.x - 80,
            top: touchLeadGhostPos.y - 20,
            background: 'var(--color-primary)',
            color: '#fff',
            borderRadius: '8px',
            padding: '8px 14px',
            fontSize: '13px',
            fontWeight: 600,
            pointerEvents: 'none',
            zIndex: 9999,
            boxShadow: '0 4px 16px rgba(0,0,0,0.25)',
            opacity: 0.9,
            maxWidth: '160px',
            whiteSpace: 'nowrap',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
          }}
        >
          {touchLeadGhostLabel}
        </div>
      )}
    </div>
  );
};

// ═══════════════════════════════════════════════════════════════════════
// CARD DO LEAD
// ═══════════════════════════════════════════════════════════════════════

interface LeadCardProps {
  lead: Lead;
  etapa: FunilEtapa;
  isDragging: boolean;
  onDragStart: () => void;
  onDragEnd: () => void;
  onTouchStart: (e: React.TouchEvent<HTMLDivElement>) => void;
  onTouchMove: (e: React.TouchEvent<HTMLDivElement>) => void;
  onTouchEnd: () => void;
  onDetalhes: () => void;
  onEditar: () => void;
  onExcluir: () => void;
  onConverter: () => void;
}

const LeadCard: React.FC<LeadCardProps> = ({
  lead, etapa, isDragging, onDragStart, onDragEnd, onTouchStart, onTouchMove, onTouchEnd,
  onDetalhes, onEditar, onExcluir, onConverter,
}) => {
  const [menuOpen, setMenuOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);
  const dias = diasDesde(lead.etapaEntradaEm);
  const semMovimento30 = dias >= 30;

  useEffect(() => {
    if (!menuOpen) return;
    const handler = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) setMenuOpen(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [menuOpen]);

  return (
    <div
      draggable={etapa.tipo !== 'perdido'}
      onDragStart={onDragStart}
      onDragEnd={onDragEnd}
      onTouchStart={etapa.tipo !== 'perdido' ? onTouchStart : undefined}
      onTouchMove={etapa.tipo !== 'perdido' ? onTouchMove : undefined}
      onTouchEnd={etapa.tipo !== 'perdido' ? onTouchEnd : undefined}
      onClick={onDetalhes}
      style={{
        background: 'var(--bg-card)',
        border: '1px solid var(--color-border)',
        borderRadius: '10px',
        padding: '12px',
        cursor: etapa.tipo !== 'perdido' ? 'grab' : 'pointer',
        touchAction: etapa.tipo !== 'perdido' ? 'none' : undefined,
        opacity: isDragging ? 0.4 : 1,
        transition: 'box-shadow 0.15s',
        position: 'relative',
      }}
      onMouseEnter={e => (e.currentTarget.style.boxShadow = '0 4px 12px rgba(0,0,0,0.08)')}
      onMouseLeave={e => (e.currentTarget.style.boxShadow = 'none')}
    >
      {/* Alerta 30 dias */}
      {semMovimento30 && (
        <div style={{
          position: 'absolute', top: '8px', right: '8px',
          background: '#FEF3C7', color: '#D97706',
          borderRadius: '100px', padding: '2px 7px',
          fontSize: '10px', fontWeight: 600,
          display: 'flex', alignItems: 'center', gap: '3px',
        }}>
          <AlertTriangle size={9} /> {dias}d parado
        </div>
      )}

      {/* Nome */}
      <div style={{ fontWeight: 600, fontSize: '13.5px', color: 'var(--color-text-main)', marginBottom: '6px', paddingRight: semMovimento30 ? '70px' : '24px' }}>
        {lead.nome}
        {lead.clienteId && (
          <span style={{ marginLeft: '6px', fontSize: '10px', background: '#D1FAE5', color: '#065F46', borderRadius: '100px', padding: '1px 6px' }}>
            Convertido
          </span>
        )}
      </div>

      {/* Procedimento */}
      {lead.procedimentoInteresse && (
        <div style={{ fontSize: '12px', color: 'var(--color-text-muted)', marginBottom: '6px' }}>
          {lead.procedimentoInteresse}
        </div>
      )}

      {/* Meta */}
      <div style={{ display: 'flex', gap: '8px', fontSize: '11px', color: 'var(--color-text-muted)', marginTop: '4px', flexWrap: 'wrap' }}>
        <span style={{ display: 'flex', alignItems: 'center', gap: '3px' }}>
          <Clock size={10} /> {formatData(lead.createdAt)}
        </span>
        {lead.responsavelNome && (
          <span style={{ display: 'flex', alignItems: 'center', gap: '3px' }}>
            <User size={10} /> {lead.responsavelNome}
          </span>
        )}
        <span style={{ marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: '3px' }}>
          <Globe size={10} /> {ORIGEM_LABELS[lead.origem]}
        </span>
      </div>

      {/* Menu ações */}
      <div
        ref={menuRef}
        style={{ position: 'absolute', bottom: '8px', right: '8px' }}
        onClick={(e) => e.stopPropagation()}
      >
        <button
          onClick={() => setMenuOpen((v) => !v)}
          style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '2px 4px', borderRadius: '4px', color: 'var(--color-text-muted)', lineHeight: 1 }}
          onMouseEnter={e => (e.currentTarget.style.background = 'var(--color-border)')}
          onMouseLeave={e => (e.currentTarget.style.background = 'none')}
        >
          <MoreHorizontal size={14} />
        </button>
        {menuOpen && (
          <div style={{
            position: 'absolute', bottom: '100%', right: 0,
            background: 'var(--bg-card)', border: '1px solid var(--color-border)',
            borderRadius: '8px', boxShadow: '0 8px 24px rgba(0,0,0,0.10)',
            padding: '4px', zIndex: 100, minWidth: '160px',
            animation: 'fadeIn 0.1s ease-out',
          }}>
            {[
              { icon: <History size={12} />, label: 'Ver histórico', action: onDetalhes },
              { icon: <Edit3 size={12} />, label: 'Editar', action: onEditar },
              ...(etapa.tipo !== 'convertido' && !lead.clienteId
                ? [{ icon: <ArrowRightCircle size={12} />, label: 'Converter', action: onConverter }]
                : []),
              { icon: <Trash2 size={12} />, label: 'Excluir', action: onExcluir, danger: true },
            ].map((item) => (
              <button
                key={item.label}
                onClick={() => { setMenuOpen(false); item.action(); }}
                style={{
                  display: 'flex', alignItems: 'center', gap: '8px',
                  width: '100%', background: 'none', border: 'none',
                  padding: '8px 10px', cursor: 'pointer', borderRadius: '6px',
                  fontSize: '12.5px', color: (item as any).danger ? '#EF4444' : 'var(--color-text-main)',
                  textAlign: 'left', fontWeight: 500,
                }}
                onMouseEnter={e => (e.currentTarget.style.background = (item as any).danger ? '#FEE2E2' : 'var(--color-primary-light)')}
                onMouseLeave={e => (e.currentTarget.style.background = 'none')}
              >
                {item.icon} {item.label}
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

// ═══════════════════════════════════════════════════════════════════════
// ITEM DE HISTÓRICO
// ═══════════════════════════════════════════════════════════════════════

const HistoricoItem: React.FC<{ item: LeadHistorico; etapas: FunilEtapa[] }> = ({ item, etapas }) => {
  const etapaNova  = etapas.find((e) => e.id === item.etapaNovaId);
  const etapaAnt   = etapas.find((e) => e.id === item.etapaAnteriorId);

  const icons: Record<LeadHistorico['tipo'], React.ReactNode> = {
    movimentacao: <ChevronRight size={12} />,
    nota:         <FileText size={12} />,
    tarefa:       <CheckSquare size={12} />,
    automacao:    <Zap size={12} />,
  };

  return (
    <div style={{ display: 'flex', gap: '10px', alignItems: 'flex-start' }}>
      <div style={{
        width: '24px', height: '24px', borderRadius: '50%', flexShrink: 0,
        background: 'var(--color-primary-light)', color: 'var(--color-primary)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
      }}>
        {icons[item.tipo]}
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ fontSize: '12.5px', color: 'var(--color-text-main)' }}>
          {item.tipo === 'movimentacao' ? (
            <>
              {etapaAnt ? <><strong>{etapaAnt.nome}</strong> → </> : 'Criado em '}
              <strong>{etapaNova?.nome ?? 'Desconhecido'}</strong>
            </>
          ) : (
            item.observacao ?? '—'
          )}
        </div>
        <div style={{ fontSize: '11px', color: 'var(--color-text-muted)', marginTop: '2px' }}>
          {item.usuarioNome} · {new Date(item.createdAt).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' })}
        </div>
      </div>
    </div>
  );
};

// ═══════════════════════════════════════════════════════════════════════
// CONFIGURAR ETAPAS
// ═══════════════════════════════════════════════════════════════════════

const EtapasConfigModal: React.FC<{
  etapas: FunilEtapa[];
  userId: string;
  onClose: () => void;
  onSave: (etapas: FunilEtapa[]) => void;
}> = ({ etapas, userId, onClose, onSave }) => {
  const [lista, setLista] = useState<FunilEtapa[]>(etapas);
  const [novo, setNovo]   = useState('');
  const [saving, setSaving] = useState(false);

  const adicionarEtapa = async () => {
    if (!novo.trim()) return;
    setSaving(true);
    try {
      const etapa = await api.createFunilEtapa({
        nome: novo, ordem: lista.length, cor: '#6B7280', tipo: 'ativo',
      }, userId);
      setLista((prev) => [...prev, etapa]);
      setNovo('');
    } catch (err) {
      alert('Erro ao criar etapa.');
    } finally {
      setSaving(false);
    }
  };

  const renomearEtapa = async (id: string, nome: string) => {
    if (!nome.trim()) return;
    try {
      const atualizada = await api.updateFunilEtapa(id, { nome }, userId);
      setLista((prev) => prev.map((e) => e.id === id ? atualizada : e));
    } catch (err) {
      alert('Erro ao renomear etapa.');
    }
  };

  const excluirEtapa = async (etapa: FunilEtapa) => {
    if (!confirm(`Excluir a etapa "${etapa.nome}"?`)) return;
    try {
      await api.deleteFunilEtapa(etapa.id, userId);
      setLista((prev) => prev.filter((e) => e.id !== etapa.id));
    } catch (err: any) {
      alert(err?.message ?? 'Erro ao excluir etapa.');
    }
  };

  return (
    <ModalOverlay onClose={onClose}>
      <div style={{ width: '440px' }}>
        <ModalHeader title="Configurar Etapas do Funil" onClose={onClose} />
        <div style={{ padding: '20px', display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {lista.map((etapa) => (
            <div key={etapa.id} style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <div style={{ width: '10px', height: '10px', borderRadius: '50%', background: etapa.cor, flexShrink: 0 }} />
              <input
                className="form-input"
                defaultValue={etapa.nome}
                onBlur={(e) => renomearEtapa(etapa.id, e.target.value)}
                style={{ flex: 1 }}
              />
              <span style={{
                fontSize: '11px', background: TIPO_COR[etapa.tipo] + '22',
                color: TIPO_COR[etapa.tipo], borderRadius: '100px', padding: '2px 8px', flexShrink: 0,
              }}>
                {etapa.tipo}
              </span>
              {etapa.tipo === 'ativo' && (
                <button onClick={() => excluirEtapa(etapa)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#EF4444', padding: '4px' }}>
                  <Trash2 size={14} />
                </button>
              )}
            </div>
          ))}

          <div style={{ display: 'flex', gap: '8px', marginTop: '8px', borderTop: '1px solid var(--color-border)', paddingTop: '12px' }}>
            <input
              className="form-input"
              value={novo}
              onChange={(e) => setNovo(e.target.value)}
              placeholder="Nome da nova etapa"
              onKeyDown={(e) => e.key === 'Enter' && adicionarEtapa()}
              style={{ flex: 1 }}
            />
            <button className="btn-primary" onClick={adicionarEtapa} disabled={saving || !novo.trim()}>
              <Plus size={14} />
            </button>
          </div>

          <div style={{ display: 'flex', justifyContent: 'flex-end', paddingTop: '8px' }}>
            <button className="btn-primary" onClick={() => onSave(lista)}>Fechar</button>
          </div>
        </div>
      </div>
    </ModalOverlay>
  );
};

// ═══════════════════════════════════════════════════════════════════════
// AUTOMAÇÕES POR ETAPA (CA-04)
// ═══════════════════════════════════════════════════════════════════════

const AutomacoesModal: React.FC<{
  etapa: FunilEtapa;
  userId: string;
  onClose: () => void;
}> = ({ etapa, userId, onClose }) => {
  const [automacoes, setAutomacoes] = useState<LeadAutomacao[]>([]);
  const [loading, setLoading]       = useState(true);
  const [criando, setCriando]       = useState(false);
  const [form, setForm] = useState<{
    tipo: LeadAutomacao['tipo'];
    gatilho: LeadAutomacao['gatilho'];
    diasEspera: string;
    mensagem: string;
    tarefaTitulo: string;
  }>({ tipo: 'tarefa', gatilho: 'ao_entrar', diasEspera: '3', mensagem: '', tarefaTitulo: '' });

  useEffect(() => {
    (async () => {
      const a = await api.getLeadAutomacoes(etapa.id, userId);
      setAutomacoes(a);
      setLoading(false);
    })();
  }, [etapa.id, userId]);

  const criar = async () => {
    setCriando(true);
    try {
      const nova = await api.createLeadAutomacao({
        etapaId:     etapa.id,
        tipo:        form.tipo,
        gatilho:     form.gatilho,
        diasEspera:  form.gatilho === 'apos_dias' ? Number(form.diasEspera) : null,
        mensagem:    form.tipo !== 'tarefa' ? form.mensagem : null,
        tarefaTitulo: form.tipo === 'tarefa' ? form.tarefaTitulo : null,
        ativo:       true,
      }, userId);
      setAutomacoes((prev) => [...prev, nova]);
      setForm({ tipo: 'tarefa', gatilho: 'ao_entrar', diasEspera: '3', mensagem: '', tarefaTitulo: '' });
    } catch (err) {
      alert('Erro ao criar automação.');
    } finally {
      setCriando(false);
    }
  };

  const toggleAtivo = async (a: LeadAutomacao) => {
    const atualizada = await api.updateLeadAutomacao(a.id, { ativo: !a.ativo }, userId);
    setAutomacoes((prev) => prev.map((x) => x.id === a.id ? atualizada : x));
  };

  const excluir = async (id: string) => {
    if (!confirm('Excluir esta automação?')) return;
    await api.deleteLeadAutomacao(id, userId);
    setAutomacoes((prev) => prev.filter((a) => a.id !== id));
  };

  const tipoIcon: Record<LeadAutomacao['tipo'], React.ReactNode> = {
    whatsapp: <MessageSquare size={12} />,
    email:    <Mail size={12} />,
    tarefa:   <CheckSquare size={12} />,
  };

  return (
    <ModalOverlay onClose={onClose}>
      <div style={{ width: '500px', maxHeight: '90vh', display: 'flex', flexDirection: 'column' }}>
        <ModalHeader title={`Automações — ${etapa.nome}`} onClose={onClose} />
        <div style={{ flex: 1, overflowY: 'auto', padding: '20px', display: 'flex', flexDirection: 'column', gap: '16px' }}>

          {/* Aviso WhatsApp/Email */}
          <div style={{ background: '#FFF7ED', border: '1px solid #FED7AA', borderRadius: '8px', padding: '10px 12px', fontSize: '12px', color: '#92400E' }}>
            <strong>Nota:</strong> Automações de WhatsApp e E-mail registram a intenção no histórico do lead.
            O envio real será ativado quando a integração WhatsApp (E3-G4) estiver disponível.
          </div>

          {/* Lista de automações */}
          {loading ? (
            <p style={{ color: 'var(--color-text-muted)', fontSize: '13px' }}>Carregando...</p>
          ) : automacoes.length === 0 ? (
            <p style={{ color: 'var(--color-text-muted)', fontSize: '13px' }}>Nenhuma automação configurada.</p>
          ) : (
            automacoes.map((a) => (
              <div key={a.id} style={{
                display: 'flex', alignItems: 'flex-start', gap: '10px',
                background: 'var(--color-bg-secondary, #F9FAFB)', borderRadius: '8px', padding: '12px',
                opacity: a.ativo ? 1 : 0.5,
              }}>
                <div style={{ color: 'var(--color-primary)', marginTop: '2px' }}>{tipoIcon[a.tipo]}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: '13px', fontWeight: 600, color: 'var(--color-text-main)' }}>
                    {a.tipo === 'tarefa' ? a.tarefaTitulo : a.mensagem}
                  </div>
                  <div style={{ fontSize: '11px', color: 'var(--color-text-muted)', marginTop: '2px' }}>
                    {a.tipo} · {a.gatilho === 'ao_entrar' ? 'ao entrar na etapa' : `após ${a.diasEspera} dias`}
                  </div>
                </div>
                <div style={{ display: 'flex', gap: '4px' }}>
                  <button onClick={() => toggleAtivo(a)} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: '11px', color: a.ativo ? '#10B981' : 'var(--color-text-muted)' }}>
                    {a.ativo ? 'Ativo' : 'Inativo'}
                  </button>
                  <button onClick={() => excluir(a.id)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#EF4444' }}>
                    <Trash2 size={12} />
                  </button>
                </div>
              </div>
            ))
          )}

          {/* Formulário nova automação */}
          <div style={{ borderTop: '1px solid var(--color-border)', paddingTop: '16px', display: 'flex', flexDirection: 'column', gap: '12px' }}>
            <h3 style={{ margin: 0, fontSize: '13px', fontWeight: 600 }}>Nova automação</h3>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
              <div className="form-group">
                <label className="form-label">Tipo</label>
                <select className="form-input" value={form.tipo} onChange={(e) => setForm((f) => ({ ...f, tipo: e.target.value as LeadAutomacao['tipo'] }))}>
                  <option value="tarefa">Tarefa (lembrete)</option>
                  <option value="whatsapp">WhatsApp</option>
                  <option value="email">E-mail</option>
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Gatilho</label>
                <select className="form-input" value={form.gatilho} onChange={(e) => setForm((f) => ({ ...f, gatilho: e.target.value as LeadAutomacao['gatilho'] }))}>
                  <option value="ao_entrar">Ao entrar na etapa</option>
                  <option value="apos_dias">Após N dias parado</option>
                </select>
              </div>
            </div>
            {form.gatilho === 'apos_dias' && (
              <div className="form-group">
                <label className="form-label">Número de dias</label>
                <input className="form-input" type="number" min="1" max="90" value={form.diasEspera}
                  onChange={(e) => setForm((f) => ({ ...f, diasEspera: e.target.value }))} />
              </div>
            )}
            <div className="form-group">
              <label className="form-label">{form.tipo === 'tarefa' ? 'Título da tarefa' : 'Mensagem'}</label>
              <textarea
                className="form-input"
                value={form.tipo === 'tarefa' ? form.tarefaTitulo : form.mensagem}
                onChange={(e) => form.tipo === 'tarefa'
                  ? setForm((f) => ({ ...f, tarefaTitulo: e.target.value }))
                  : setForm((f) => ({ ...f, mensagem: e.target.value }))}
                placeholder={form.tipo === 'tarefa' ? 'Ex: Ligar para o lead' : 'Texto da mensagem...'}
                rows={2}
              />
            </div>
            <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
              <button className="btn-primary" onClick={criar} disabled={criando}
                style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px' }}>
                <Plus size={13} /> {criando ? 'Criando...' : 'Adicionar automação'}
              </button>
            </div>
          </div>
        </div>
      </div>
    </ModalOverlay>
  );
};

// ═══════════════════════════════════════════════════════════════════════
// UTILITÁRIOS DE UI
// ═══════════════════════════════════════════════════════════════════════

const ModalOverlay: React.FC<{ children: React.ReactNode; onClose: () => void }> = ({ children, onClose }) => (
  <div
    className="modal-overlay"
    style={{
      position: 'fixed', inset: 0, zIndex: 1000,
      background: 'rgba(0,0,0,0.35)',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      padding: '20px',
      animation: 'fadeIn 0.15s ease-out',
    }}
    onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
  >
    <div
      className="modal-inner"
      style={{
        background: 'var(--bg-card)',
        borderRadius: '16px',
        boxShadow: '0 20px 60px rgba(0,0,0,0.15)',
        overflowY: 'auto',
        maxHeight: '95vh',
        maxWidth: '96vw',
      }}
    >
      {children}
    </div>
  </div>
);

const ModalHeader: React.FC<{ title: string; onClose: () => void }> = ({ title, onClose }) => (
  <div style={{
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    padding: '18px 20px 14px',
    borderBottom: '1px solid var(--color-border)',
  }}>
    <h2 style={{ margin: 0, fontSize: '16px', fontWeight: 700, color: 'var(--color-text-main)' }}>{title}</h2>
    <button onClick={onClose} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--color-text-muted)', padding: '4px', borderRadius: '6px' }}>
      <X size={18} />
    </button>
  </div>
);

const InfoItem: React.FC<{ icon: React.ReactNode; label: string; value: string }> = ({ icon, label, value }) => (
  <div style={{ background: 'var(--color-bg-secondary, #F9FAFB)', borderRadius: '8px', padding: '10px 12px' }}>
    <div style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '11px', color: 'var(--color-text-muted)', marginBottom: '3px' }}>
      {icon} {label}
    </div>
    <div style={{ fontSize: '13px', fontWeight: 500, color: 'var(--color-text-main)', wordBreak: 'break-word' }}>{value}</div>
  </div>
);

