                    </div>
                    <div style={{ height: '6px', background: '#F0F0F0', borderRadius: '3px', overflow: 'hidden' }}>
                      <div style={{ width: `${p.percentual}%`, height: '100%', background: i === 0 ? 'var(--color-primary)' : '#BACBC5' }} />
