type PeriodoPreset = '6meses' | '12meses' | 'historico' | 'personalizado';
type ViewTab = 'dashboard' | 'ltv-paciente' | 'segmentacao';
type RankOrdem = 'receita' | 'atendimentos' | 'ticket';
type FaixaLTV = 'bronze' | 'prata' | 'ouro';

interface LTVPaciente {
  clienteId: string;
