  async getAgendamentosRange(
    userId: string | undefined,
    inicio: string,
    fim: string
  ): Promise<Agendamento[]> {
    return run(async () => {
      const uid = await requireUserId(userId);
      const { data, error } = await supabase
        .from('agendamentos')
        .select('*, clientes ( nome, foto_url ), salas ( nome )')
        .eq('user_id', uid)
        .gte('data', inicio)
        .lte('data', fim)
        .order('data')
        .order('hora_inicio');
      if (error) throw error;
      return (data ?? []).map(mapAgendamento);
    });
  },

  async createAgendamento(
    agendamento: Omit<Agendamento, 'id' | 'clienteNome' | 'clienteFoto'>,
    userId?: string
  ): Promise<Agendamento> {
    return run(async () => {
      const uid = await requireUserId(userId);
      if (!agendamento.clienteId) {
        throw new ApiError('Selecione o cliente antes de criar o agendamento.', 400);
      }

      // Trava de conflito (autoridade): pacientes, profissionais e salas não podem se sobrepor
      const { data: existentes, error: fetchError } = await supabase
        .from('agendamentos')
        .select('*, clientes ( nome, foto_url ), salas ( nome )')
        .eq('user_id', uid)
        .eq('data', agendamento.data);
      if (fetchError) throw fetchError;

      const conflito = findAgendamentoConflict(
        {
          clienteId: agendamento.clienteId,
          profissional: agendamento.profissional,
          data: agendamento.data,
          horaInicio: agendamento.horaInicio,
          horaFim: agendamento.horaFim,
          roomId: agendamento.roomId,
        },
        (existentes ?? []).map(mapAgendamento)
      );
      if (conflito) {
        throw new ApiError(conflito.mensagem, 409, 'AGENDAMENTO_CONFLITO');
      }

      const { data, error } = await supabase
        .from('agendamentos')
        .insert([
          {
            user_id: uid,
            cliente_id: agendamento.clienteId,
            data: agendamento.data,
            hora_inicio: agendamento.horaInicio,
            hora_fim: agendamento.horaFim,
            profissional: agendamento.profissional,
            sala: agendamento.sala,
            room_id: agendamento.roomId ?? null,
            procedimento: agendamento.procedimento,
            status: agendamento.status,
            tempo_espera_minutos: agendamento.tempoEsperaMinutos ?? null,
            horario_chegada: agendamento.horarioChegada ?? null,
            valor: agendamento.valor,
          },
        ])
        .select('*, clientes ( nome, foto_url ), salas ( nome )')
        .single();
      if (error) throw error;
      return mapAgendamento(data);
    });
  },

  async updateAgendamentoStatus(
    id: string,
    updates: Partial<Agendamento>,
    userId?: string
  ): Promise<Agendamento> {
    return run(async () => {
      const uid = await requireUserId(userId);
      const dbUpdates: Record<string, unknown> = {};
      if (updates.status !== undefined) dbUpdates.status = updates.status;
      if (updates.horarioChegada !== undefined) dbUpdates.horario_chegada = updates.horarioChegada;
      if (updates.tempoEsperaMinutos !== undefined)
        dbUpdates.tempo_espera_minutos = updates.tempoEsperaMinutos;
      if (updates.metodoPagamento !== undefined)
        dbUpdates.metodo_pagamento = updates.metodoPagamento;

      const { data, error } = await supabase
        .from('agendamentos')
        .update(dbUpdates)
        .eq('id', id)
        .eq('user_id', uid)
        .select('*, clientes ( nome, foto_url )')
        .single();
      if (error) throw error;

      if (updates.status === 'finalizada' && data?.cliente_id) {
        await supabase
          .from('clientes')
          .update({ data_ultima_visita: data.data })
          .eq('id', data.cliente_id)
          .eq('user_id', uid);

        // US-034: calcula e registra comissão automaticamente no checkout
        await calcularComissaoCheckout(uid, {
          id: data.id,
          profissional: data.profissional ?? '',
          procedimento: data.procedimento ?? '',
          valor: Number(data.valor ?? 0),
          data: data.data,
        });
      }

      return mapAgendamento(data);
    });
  },

  async updateAgendamentoDados(
    id: string,
    updates: { horaInicio?: string; horaFim?: string; procedimento?: string; profissional?: string; sala?: string },
    userId?: string
  ): Promise<Agendamento> {
    return run(async () => {
      const uid = await requireUserId(userId);

      const precisaValidar =
        updates.horaInicio !== undefined ||
        updates.horaFim !== undefined ||
        updates.profissional !== undefined ||
        updates.sala !== undefined;

      if (precisaValidar) {
        const { data: atual, error: fetchAtualErr } = await supabase
          .from('agendamentos')
          .select('*, clientes ( nome, foto_url )')
          .eq('id', id)
          .eq('user_id', uid)
          .single();
        if (fetchAtualErr) throw fetchAtualErr;
        const atualMapped = mapAgendamento(atual);

        const { data: existentes, error: listErr } = await supabase
          .from('agendamentos')
          .select('*, clientes ( nome, foto_url )')
          .eq('user_id', uid)
          .eq('data', atualMapped.data);
        if (listErr) throw listErr;

        const agExistentes = (existentes ?? []).map(mapAgendamento);

        const conflito = findAgendamentoConflict(
          {
            clienteId: atualMapped.clienteId,
            profissional: updates.profissional ?? atualMapped.profissional,
            data: atualMapped.data,
            horaInicio: updates.horaInicio ?? atualMapped.horaInicio,
            horaFim: updates.horaFim ?? atualMapped.horaFim,
          },
          agExistentes,
          id
        );
        if (conflito) {
          throw new ApiError(conflito.mensagem, 409, 'AGENDAMENTO_CONFLITO');
        }

        // Validate sala conflict when sala is being changed
        if (updates.sala !== undefined && updates.sala !== atualMapped.sala) {
          const horaInicio = updates.horaInicio ?? atualMapped.horaInicio;
          const horaFim = updates.horaFim ?? atualMapped.horaFim;
          const [salaStatus] = getSalasStatus([updates.sala], atualMapped.data, horaInicio, horaFim, agExistentes, id);
          if (salaStatus && !salaStatus.disponivel) {
            throw new ApiError(
              `Sala "${updates.sala}" já está ocupada neste horário (${salaStatus.ocupadaPor}). Escolha outra sala ou mude o horário.`,
              409,
              'SALA_CONFLITO'
            );
          }
        }
      }

      const dbUpdates: Record<string, unknown> = {};
      if (updates.horaInicio !== undefined) dbUpdates.hora_inicio = updates.horaInicio;
      if (updates.horaFim !== undefined) dbUpdates.hora_fim = updates.horaFim;
      if (updates.procedimento !== undefined) dbUpdates.procedimento = updates.procedimento;
      if (updates.profissional !== undefined) dbUpdates.profissional = updates.profissional;
      if (updates.sala !== undefined) {
        // Fetch current sala for audit entry before overwriting
        const { data: curr } = await supabase
          .from('agendamentos')
          .select('sala, sala_historico')
          .eq('id', id)
          .eq('user_id', uid)
          .single();
        const prevSala: string = (curr as { sala?: string } | null)?.sala ?? '';
        if (prevSala !== updates.sala) {
          const historico: unknown[] = Array.isArray((curr as { sala_historico?: unknown[] } | null)?.sala_historico)
            ? ((curr as { sala_historico: unknown[] }).sala_historico)
            : [];
          historico.push({ from: prevSala, to: updates.sala, changedAt: new Date().toISOString() });
          dbUpdates.sala_historico = historico;
        }
        dbUpdates.sala = updates.sala;
      }

      const { data, error } = await supabase
        .from('agendamentos')
        .update(dbUpdates)
        .eq('id', id)
        .eq('user_id', uid)
        .select('*, clientes ( nome, foto_url )')
        .single();
      if (error) throw error;
      return mapAgendamento(data);
    });
  },

  async deleteAgendamento(id: string, userId?: string): Promise<void> {
    return run(async () => {
      const uid = await requireUserId(userId);
      const { error } = await supabase
        .from('agendamentos')
        .delete()
        .eq('id', id)
        .eq('user_id', uid);
      if (error) throw error;
    });
  },

