  async dispararAutomacoesEtapa(
    leadId: string,
    etapaId: string,
    usuarioNome: string,
    userId?: string
  ): Promise<void> {
    return run(async () => {
      const uid = await requireUserId(userId);
      const { data: automacoes } = await supabase
