    conduta: juntar(secoes.conduta, '(Nenhuma conduta identificada automaticamente.)'),
    prescricao: juntar(secoes.prescricao, '(Nenhuma prescrição identificada automaticamente.)'),
    cid10Sugestoes: sugerirCID10(transcricao),
  };
}

